#[test]
fn ephemeral_database_executes_basic_sql() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(&db, "create table items (id int, name text)")
        .expect("create table");
    session
        .execute(&db, "insert into items values (1, 'a'), (2, 'b')")
        .expect("insert rows");

    let result = session
        .execute(&db, "select id, name from items order by id")
        .expect("select rows");
    let StatementResult::Query { rows, .. } = result else {
        panic!("expected query result");
    };
    assert_eq!(
        rows,
        vec![
            vec![Value::Int32(1), Value::Text("a".into())],
            vec![Value::Int32(2), Value::Text("b".into())],
        ]
    );
}

#[test]
fn prepared_transaction_commit_and_rollback_control_visibility() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut writer = Session::new(1);
    let mut observer = Session::new(2);

    writer
        .execute(&db, "create table two_pc_items (id int)")
        .unwrap();
    writer.execute(&db, "begin").unwrap();
    writer
        .execute(&db, "insert into two_pc_items values (1)")
        .unwrap();
    writer
        .execute(&db, "prepare transaction 'commit-gid'")
        .unwrap();

    assert!(!writer.in_transaction());
    assert_eq!(
        session_query_rows(&mut observer, &db, "select count(*) from two_pc_items"),
        vec![vec![Value::Int64(0)]]
    );
    assert_eq!(
        session_query_rows(
            &mut observer,
            &db,
            "select gid from pg_prepared_xacts order by gid"
        ),
        vec![vec![Value::Text("commit-gid".into())]]
    );
    observer
        .execute(&db, "commit prepared 'commit-gid'")
        .unwrap();
    assert_eq!(
        session_query_rows(&mut observer, &db, "select count(*) from two_pc_items"),
        vec![vec![Value::Int64(1)]]
    );

    writer.execute(&db, "begin").unwrap();
    writer
        .execute(&db, "insert into two_pc_items values (2)")
        .unwrap();
    writer
        .execute(&db, "prepare transaction 'rollback-gid'")
        .unwrap();
    observer
        .execute(&db, "rollback prepared 'rollback-gid'")
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut observer,
            &db,
            "select id from two_pc_items order by id"
        ),
        vec![vec![Value::Int32(1)]]
    );
}

#[test]
fn prepared_transaction_rejects_duplicate_gid_and_finish_inside_transaction() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut first = Session::new(1);
    let mut second = Session::new(2);

    first
        .execute(&db, "create table two_pc_dups (id int)")
        .unwrap();
    first.execute(&db, "begin").unwrap();
    first
        .execute(&db, "insert into two_pc_dups values (1)")
        .unwrap();
    first
        .execute(&db, "prepare transaction 'same-gid'")
        .unwrap();

    second.execute(&db, "begin").unwrap();
    second
        .execute(&db, "insert into two_pc_dups values (2)")
        .unwrap();
    let err = second
        .execute(&db, "prepare transaction 'same-gid'")
        .unwrap_err();
    match err {
        ExecError::DetailedError {
            message, sqlstate, ..
        } => {
            assert_eq!(sqlstate, "42710");
            assert!(message.contains("same-gid"));
        }
        other => panic!("expected duplicate prepared xact error, got {other:?}"),
    }
    second.execute(&db, "rollback").unwrap();

    second.execute(&db, "begin").unwrap();
    let err = second
        .execute(&db, "commit prepared 'same-gid'")
        .unwrap_err();
    match err {
        ExecError::DetailedError {
            message, sqlstate, ..
        } => {
            assert_eq!(sqlstate, "25001");
            assert_eq!(
                message,
                "COMMIT PREPARED cannot run inside a transaction block"
            );
        }
        other => panic!("expected active transaction error, got {other:?}"),
    }
    second.execute(&db, "rollback").unwrap();
    second.execute(&db, "commit prepared 'same-gid'").unwrap();
}

#[test]
fn durable_prepared_transaction_survives_reopen_then_finishes() {
    let dir = temp_dir("durable_prepared_transaction_survives_reopen_then_finishes");
    {
        let db = Database::open(&dir, 32).expect("open durable database");
        let mut session = Session::new(1);
        session
            .execute(&db, "create table durable_two_pc (id int)")
            .unwrap();
        session.execute(&db, "begin").unwrap();
        session
            .execute(&db, "insert into durable_two_pc values (7)")
            .unwrap();
        session
            .execute(&db, "prepare transaction 'durable-gid'")
            .unwrap();
        assert_eq!(
            session_query_rows(&mut session, &db, "select gid from pg_prepared_xacts"),
            vec![vec![Value::Text("durable-gid".into())]]
        );
    }
    {
        let db = Database::open(&dir, 32).expect("reopen durable database");
        let mut session = Session::new(2);
        assert_eq!(
            session_query_rows(&mut session, &db, "select gid from pg_prepared_xacts"),
            vec![vec![Value::Text("durable-gid".into())]]
        );
        session
            .execute(&db, "commit prepared 'durable-gid'")
            .unwrap();
        assert_eq!(
            session_query_rows(&mut session, &db, "select id from durable_two_pc"),
            vec![vec![Value::Int32(7)]]
        );
    }
}

#[test]
fn prepared_transaction_retains_drop_table_lock_until_finish() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut dropper = Session::new(1);
    let mut waiter = Session::new(2);

    dropper
        .execute(&db, "create table two_pc_drop_lock (id int)")
        .unwrap();
    dropper.execute(&db, "begin").unwrap();
    dropper.execute(&db, "drop table two_pc_drop_lock").unwrap();
    dropper
        .execute(&db, "prepare transaction 'drop-lock-gid'")
        .unwrap();

    waiter.execute(&db, "begin").unwrap();
    let err = waiter
        .execute(
            &db,
            "lock table two_pc_drop_lock in access share mode nowait",
        )
        .unwrap_err();
    match err {
        ExecError::DetailedError {
            message, sqlstate, ..
        } => {
            assert_eq!(sqlstate, "55P03");
            assert_eq!(
                message,
                "could not obtain lock on relation \"two_pc_drop_lock\""
            );
        }
        other => panic!("expected lock-not-available error, got {other:?}"),
    }
    waiter.execute(&db, "rollback").unwrap();
    waiter
        .execute(&db, "commit prepared 'drop-lock-gid'")
        .unwrap();

    let err = waiter
        .execute(&db, "select * from two_pc_drop_lock")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::Parse(ParseError::TableDoesNotExist(_))
            | ExecError::Parse(ParseError::UnknownTable(_))
    ));
}

#[test]
fn prepared_transaction_retains_row_lock_for_nowait() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut locker = Session::new(1);
    let mut waiter = Session::new(2);

    locker
        .execute(
            &db,
            "create table two_pc_row_lock (id int primary key, data text)",
        )
        .unwrap();
    locker
        .execute(&db, "insert into two_pc_row_lock values (1, 'held')")
        .unwrap();
    locker.execute(&db, "begin").unwrap();
    locker
        .execute(&db, "select * from two_pc_row_lock where id = 1 for share")
        .unwrap();
    locker
        .execute(&db, "prepare transaction 'row-lock-gid'")
        .unwrap();

    let err = waiter
        .execute(
            &db,
            "select * from two_pc_row_lock where id = 1 for update nowait",
        )
        .unwrap_err();
    match err {
        ExecError::DetailedError {
            message, sqlstate, ..
        } => {
            assert_eq!(sqlstate, "55P03");
            assert_eq!(
                message,
                "could not obtain lock on row in relation \"two_pc_row_lock\""
            );
        }
        other => panic!("expected row lock-not-available error, got {other:?}"),
    }

    waiter
        .execute(&db, "rollback prepared 'row-lock-gid'")
        .unwrap();
}

#[test]
fn session_setseed_affects_following_random_statement() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select oid, prosrc from pg_proc where proname = 'setseed'",
        ),
        vec![vec![Value::Int64(1599), Value::Text("setseed".into())]]
    );
    session
        .execute(&db, "select setseed(0.5)")
        .expect("seed random state");
    let result = session
        .execute(&db, "select random() from generate_series(1, 3)")
        .expect("read seeded random values");
    let StatementResult::Query { rows, .. } = result else {
        panic!("expected query result");
    };
    assert_eq!(rows.len(), 3);
    let expected = [0.9851677175347999, 0.825301858027981, 0.12974610012450416];
    for (row, expected) in rows.iter().zip(expected) {
        match row.first() {
            Some(Value::Float64(actual)) => assert_eq!(*actual, expected),
            other => panic!("expected float8 random value, got {other:?}"),
        }
    }
}

#[test]
fn cte_order_by_feeds_row_number_in_materialized_order() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    let rows = session_query_rows(
        &mut session,
        &db,
        "
            with samples as (
                select column1 r from (values (3), (1), (2)) v order by 1
            ), indexed_samples as (
                select row_number() over () i, r from samples
            )
            select i, r from indexed_samples
            ",
    );
    assert_eq!(
        rows,
        vec![
            vec![Value::Int64(1), Value::Int32(1)],
            vec![Value::Int64(2), Value::Int32(2)],
            vec![Value::Int64(3), Value::Int32(3)],
        ],
    );
}

#[test]
fn order_by_ordinal_sorts_projected_volatile_value() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    let rows = session_query_rows(
        &mut session,
        &db,
        "select random() r from generate_series(1, 50) order by 1",
    );
    let values = rows
        .iter()
        .map(|row| match row.as_slice() {
            [Value::Float64(value)] => *value,
            other => panic!("expected one float8 column, got {other:?}"),
        })
        .collect::<Vec<_>>();
    assert!(
        values.windows(2).all(|pair| pair[0] <= pair[1]),
        "ORDER BY 1 must sort the projected random() values: {values:?}"
    );
}

#[test]
fn generated_columns_compute_on_insert_update_and_read() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table stored_generated (a int4, b int4 generated always as (a + 1) stored)",
        )
        .expect("create stored generated table");
    session
        .execute(&db, "insert into stored_generated(a) values (4)")
        .expect("insert generated row");
    session
        .execute(&db, "insert into stored_generated values (5, default)")
        .expect("insert generated default row");
    assert_single_int_column_rows(
        session
            .execute(&db, "select b from stored_generated order by a")
            .expect("select stored generated rows"),
        vec![vec![Value::Int32(5)], vec![Value::Int32(6)]],
    );

    session
        .execute(&db, "update stored_generated set a = 9 where a = 4")
        .expect("update generated row");
    assert_single_int_column_rows(
        session
            .execute(&db, "select b from stored_generated where a = 9")
            .expect("select updated generated row"),
        vec![vec![Value::Int32(10)]],
    );

    let err = session
        .execute(&db, "insert into stored_generated values (7, 99)")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::Parse(ParseError::DetailedError {
            sqlstate: "428C9",
            ..
        })
    ));

    session
        .execute(
            &db,
            "create table virtual_generated (a int4, b int4 generated always as (a + 1))",
        )
        .expect("create virtual generated table");
    session
        .execute(&db, "insert into virtual_generated(a) values (11)")
        .expect("insert virtual generated row");
    assert_single_int_column_rows(
        session
            .execute(&db, "select b from virtual_generated where b = 12")
            .expect("select virtual generated row"),
        vec![vec![Value::Int32(12)]],
    );
}

#[test]
fn alter_table_generated_columns_support_staged_type_batches() {
    fn run(kind: &str) {
        let db = Database::open_ephemeral(32).unwrap();

        db.execute(1, "create table gtest25 (a int primary key)")
            .unwrap();
        db.execute(1, "insert into gtest25 values (3), (4)")
            .unwrap();
        db.execute(
            1,
            &format!(
                "alter table gtest25
                   add column b int generated always as (a * 2) {kind},
                   alter column b set expression as (a * 3)"
            ),
        )
        .unwrap();
        assert_eq!(
            query_rows(&db, 1, "select a, b from gtest25 order by a"),
            vec![
                vec![Value::Int32(3), Value::Int32(9)],
                vec![Value::Int32(4), Value::Int32(12)],
            ]
        );

        db.execute(
            1,
            &format!(
                "alter table gtest25
                   add column c int default 42,
                   add column x int generated always as (c * 4) {kind}"
            ),
        )
        .unwrap();
        assert_eq!(
            query_rows(&db, 1, "select c, x from gtest25 order by a"),
            vec![
                vec![Value::Int32(42), Value::Int32(168)],
                vec![Value::Int32(42), Value::Int32(168)],
            ]
        );

        db.execute(1, "alter table gtest25 add column d int default 101")
            .unwrap();
        db.execute(
            1,
            &format!(
                "alter table gtest25
                   alter column d type float8,
                   add column y float8 generated always as (d * 4) {kind}"
            ),
        )
        .unwrap();
        assert_eq!(
            query_rows(&db, 1, "select d, y from gtest25 order by a"),
            vec![
                vec![Value::Float64(101.0), Value::Float64(404.0)],
                vec![Value::Float64(101.0), Value::Float64(404.0)],
            ]
        );

        db.execute(
            1,
            &format!(
                "create table gtest27 (
                    a int,
                    b int,
                    x int generated always as ((a + b) * 2) {kind}
                )"
            ),
        )
        .unwrap();
        db.execute(1, "insert into gtest27 (a, b) values (3, 7), (4, 11)")
            .unwrap();
        assert!(
            db.execute(1, "alter table gtest27 alter column a type text")
                .is_err()
        );
        db.execute(1, "alter table gtest27 alter column x type numeric")
            .unwrap();
        assert_eq!(
            query_rows(
                &db,
                1,
                "select atttypid::regtype::text
                 from pg_attribute
                 where attrelid = 'gtest27'::regclass and attname = 'x'",
            ),
            vec![vec![Value::Text("numeric".into())]]
        );
        match db.execute(
            1,
            "alter table gtest27 alter column x type boolean using x <> 0",
        ) {
            Err(ExecError::DetailedError {
                message, sqlstate, ..
            }) => {
                assert_eq!(
                    message,
                    "cannot specify USING when altering type of generated column"
                );
                assert_eq!(sqlstate, "42601");
            }
            other => panic!("expected generated USING rejection, got {other:?}"),
        }

        db.execute(
            1,
            &format!(
                "alter table gtest27
                   drop column x,
                   alter column a type bigint,
                   alter column b type bigint,
                   add column x bigint generated always as ((a + b) * 2) {kind}"
            ),
        )
        .unwrap();
        assert_eq!(
            query_rows(&db, 1, "select a, b, x from gtest27 order by a"),
            vec![
                vec![Value::Int64(3), Value::Int64(7), Value::Int64(20)],
                vec![Value::Int64(4), Value::Int64(11), Value::Int64(30)],
            ]
        );
    }

    run("stored");
    run("virtual");
}

#[test]
fn alter_table_generated_set_expression_rewrites_and_validates_rows() {
    for kind in ["stored", "virtual"] {
        let db = Database::open_ephemeral(32).unwrap();
        let mut session = Session::new(1);

        session
            .execute(
                &db,
                &format!(
                    "create table gset (
                    a int,
                    b int generated always as (a * 2) {kind},
                    check (b < 10)
                )"
                ),
            )
            .unwrap();
        session
            .execute(&db, "insert into gset (a) values (4)")
            .unwrap();
        match session.execute(
            &db,
            "alter table gset alter column b set expression as (a * 3)",
        ) {
            Err(ExecError::CheckViolation { constraint, .. }) => {
                assert_eq!(constraint, "gset_b_check");
            }
            other => panic!("expected SET EXPRESSION check failure, got {other:?}"),
        }
        assert_eq!(
            query_rows(&db, 1, "select b from gset"),
            vec![vec![Value::Int32(8)]]
        );

        session
            .execute(
                &db,
                "alter table gset alter column b set expression as (a + 1)",
            )
            .unwrap();
        assert_eq!(
            query_rows(&db, 1, "select b from gset"),
            vec![vec![Value::Int32(5)]]
        );

        if kind == "stored" {
            session
                .execute(
                    &db,
                    "create table gnn (
                    a int,
                    b int generated always as (a) stored not null
                )",
                )
                .unwrap();
            session
                .execute(&db, "insert into gnn (a) values (1)")
                .unwrap();
            match session.execute(
                &db,
                "alter table gnn alter column b set expression as (nullif(a, 1))",
            ) {
                Err(ExecError::NotNullViolation { column, .. }) => {
                    assert_eq!(column, "b");
                }
                other => panic!("expected SET EXPRESSION not-null failure, got {other:?}"),
            }
        }
    }
}

#[test]
fn generated_columns_keep_view_dml_and_merge_returning_semantics() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table stored_view_base (a int4 primary key, b int4 generated always as (a * 2) stored)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create view stored_view as select * from stored_view_base",
        )
        .unwrap();
    session
        .execute(&db, "insert into stored_view values (1, default)")
        .unwrap();
    let stored_explicit = session
        .execute(&db, "insert into stored_view values (2, 4)")
        .unwrap_err();
    assert!(matches!(
        stored_explicit,
        ExecError::Parse(ParseError::DetailedError {
            sqlstate: "428C9",
            ..
        })
    ));
    let stored_multi = session
        .execute(&db, "insert into stored_view values (2, default), (3, 6)")
        .unwrap_err();
    assert!(matches!(
        stored_multi,
        ExecError::Parse(ParseError::DetailedError {
            sqlstate: "428C9",
            ..
        })
    ));
    assert_eq!(
        session_query_rows(&mut session, &db, "select * from stored_view order by a"),
        vec![vec![Value::Int32(1), Value::Int32(2)]]
    );

    session
        .execute(
            &db,
            "create table virtual_view_base (a int4 primary key, b int4 generated always as (a * 2) virtual)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create view virtual_view as select * from virtual_view_base",
        )
        .unwrap();
    session
        .execute(&db, "insert into virtual_view values (1, default)")
        .unwrap();
    let virtual_explicit = session
        .execute(&db, "insert into virtual_view values (2, 4)")
        .unwrap_err();
    assert!(matches!(
        virtual_explicit,
        ExecError::Parse(ParseError::DetailedError {
            sqlstate: "428C9",
            ..
        })
    ));
    assert_eq!(
        session_query_rows(&mut session, &db, "select * from virtual_view order by a"),
        vec![vec![Value::Int32(1), Value::Int32(2)]]
    );

    session
        .execute(
            &db,
            "create table merge_virtual (
                id int4 primary key,
                f1 int4,
                f2 int4,
                f3 int4 generated always as (f1 * 2) virtual,
                f4 int4 generated always as (f2 * 2) virtual
            )",
        )
        .unwrap();
    session
        .execute(&db, "insert into merge_virtual values (1, 5, 100)")
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "merge into merge_virtual t using (values (1, 10), (2, 20)) v(id, f1) on t.id = v.id
               when matched then update set f1 = v.f1
               when not matched then insert values (v.id, v.f1, 200)
               returning merge_action(), old.f3, old.f4, new.f3, new.f4"
        ),
        vec![
            vec![
                Value::Text("UPDATE".into()),
                Value::Int32(10),
                Value::Int32(200),
                Value::Int32(20),
                Value::Int32(200),
            ],
            vec![
                Value::Text("INSERT".into()),
                Value::Null,
                Value::Null,
                Value::Int32(40),
                Value::Int32(400),
            ],
        ]
    );
}

