#[test]
fn pg_signal_backend_role_cannot_terminate_superuser_backend() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(41);
    db.install_auth_state(43, AuthState::default());
    db.install_interrupt_state(
        43,
        Arc::new(crate::backend::utils::misc::interrupts::InterruptState::new()),
    );
    db.set_session_query_active(43, "select 1", None);

    session.execute(&db, "begin").unwrap();
    session
        .execute(
            &db,
            r#"CREATE OR REPLACE FUNCTION terminate_nothrow(pid int) RETURNS bool
	LANGUAGE plpgsql SECURITY DEFINER SET client_min_messages = error AS $$
BEGIN
	RETURN pg_terminate_backend($1);
EXCEPTION WHEN OTHERS THEN
	RETURN false;
END$$"#,
        )
        .unwrap();
    session
        .execute(
            &db,
            "ALTER FUNCTION terminate_nothrow OWNER TO pg_signal_backend",
        )
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "SELECT backend_type FROM pg_stat_activity
WHERE pid = 43
  AND CASE WHEN COALESCE(usesysid, 10) = 10 THEN terminate_nothrow(pid) END"
        ),
        Vec::<Vec<Value>>::new()
    );
    session.execute(&db, "rollback").unwrap();
}

#[test]
fn txid_snapshot_type_round_trips_and_validates_visibility() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(&db, "create temp table snapshot_test (snap txid_snapshot)")
        .unwrap();
    session
        .execute(&db, "insert into snapshot_test values ('12:16:14,14')")
        .unwrap();

    assert_eq!(
        session_query_rows(&mut session, &db, "select snap from snapshot_test"),
        vec![vec![Value::Text("12:16:14".into())]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select txid_snapshot_xmin(snap), txid_snapshot_xmax(snap), txid_snapshot_xip(snap) from snapshot_test",
        ),
        vec![vec![Value::Xid8(12), Value::Xid8(16), Value::Xid8(14)]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select txid_visible_in_snapshot(13, '12:20:13,15,18'::txid_snapshot), \
                    txid_visible_in_snapshot(14, '12:20:13,15,18'::txid_snapshot), \
                    pg_input_is_valid('12:16:14,13', 'txid_snapshot')",
        ),
        vec![vec![
            Value::Bool(false),
            Value::Bool(true),
            Value::Bool(false),
        ]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select txid_visible_in_snapshot('1000100010001012', \
                    '1000100010001000:1000100010001100:1000100010001012,1000100010001013'), \
                    txid_visible_in_snapshot('1000100010001015', \
                    '1000100010001000:1000100010001100:1000100010001012,1000100010001013')",
        ),
        vec![vec![Value::Bool(false), Value::Bool(true)]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select txid_current() >= txid_snapshot_xmin(txid_current_snapshot()), \
                    txid_visible_in_snapshot(txid_current(), txid_current_snapshot())",
        ),
        vec![vec![Value::Bool(true), Value::Bool(false)]]
    );
}

#[test]
fn txid_current_and_if_assigned_follow_lazy_xid_assignment() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session.execute(&db, "begin").unwrap();

    assert_eq!(
        session_query_rows(&mut session, &db, "select txid_current_if_assigned()"),
        vec![vec![Value::Null]]
    );

    let rows = session_query_rows(&mut session, &db, "select txid_current()");
    let txid = match &rows[..] {
        [row] => match &row[..] {
            [Value::Xid8(txid)] => *txid,
            other => panic!("expected xid8 txid_current result, got {other:?}"),
        },
        other => panic!("expected one txid_current row, got {other:?}"),
    };

    assert_eq!(
        session_query_rows(&mut session, &db, "select txid_current_if_assigned()"),
        vec![vec![Value::Xid8(txid)]]
    );

    session.execute(&db, "commit").unwrap();
}

