#[test]
fn repeatable_read_reuses_first_snapshot() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut reader = Session::new(1);

    db.execute(10, "create table rr_items (id int4 not null)")
        .unwrap();
    db.execute(10, "insert into rr_items values (1)").unwrap();

    reader
        .execute(&db, "begin isolation level repeatable read")
        .unwrap();
    assert_eq!(
        session_query_rows(&mut reader, &db, "select count(*) from rr_items"),
        vec![vec![Value::Int64(1)]]
    );

    db.execute(20, "insert into rr_items values (2)").unwrap();

    assert_eq!(
        session_query_rows(&mut reader, &db, "select count(*) from rr_items"),
        vec![vec![Value::Int64(1)]]
    );
    reader.execute(&db, "commit").unwrap();

    assert_eq!(
        query_rows(&db, 30, "select count(*) from rr_items"),
        vec![vec![Value::Int64(2)]]
    );
}

#[test]
fn repeatable_read_streaming_uses_transaction_snapshot() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut reader = Session::new(1);

    db.execute(10, "create table rr_streaming (id int4 not null)")
        .unwrap();
    db.execute(10, "insert into rr_streaming values (1)")
        .unwrap();

    reader
        .execute(&db, "begin isolation level repeatable read")
        .unwrap();
    assert_eq!(
        session_query_rows(&mut reader, &db, "select count(*) from rr_streaming"),
        vec![vec![Value::Int64(1)]]
    );

    db.execute(20, "insert into rr_streaming values (2)")
        .unwrap();

    let stmt = crate::backend::parser::parse_select("select count(*) from rr_streaming").unwrap();
    let mut guard = reader.execute_streaming(&db, &stmt).unwrap();
    let slot = crate::backend::executor::exec_next(&mut guard.state, &mut guard.ctx)
        .unwrap()
        .expect("streaming count row");
    let values = slot.values().unwrap();
    assert_eq!(values[0].to_owned_value(), Value::Int64(1));
    assert!(
        crate::backend::executor::exec_next(&mut guard.state, &mut guard.ctx)
            .unwrap()
            .is_none()
    );
    drop(guard);

    reader.execute(&db, "commit").unwrap();
}

#[test]
fn streaming_select_clears_subquery_membership_cache_between_statements() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table stream_cache_parent (id int primary key) partition by range (id)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table stream_cache_child partition of stream_cache_parent for values from (0) to (10)",
        )
        .unwrap();
    assert_eq!(
        streaming_query_rows(
            &mut session,
            &db,
            "select cr.relname \
               from pg_class cr \
              where cr.oid in (select relid from pg_partition_tree('stream_cache_parent')) \
              order by cr.relname",
        ),
        vec![
            vec![Value::Text("stream_cache_child".into())],
            vec![Value::Text("stream_cache_parent".into())],
        ]
    );

    session
        .execute(&db, "drop table stream_cache_parent")
        .unwrap();
    session
        .execute(
            &db,
            "create table stream_live_parent (id int primary key) partition by range (id)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table stream_live_child partition of stream_live_parent for values from (0) to (10)",
        )
        .unwrap();
    assert_eq!(
        streaming_query_rows(
            &mut session,
            &db,
            "select cr.relname \
               from pg_class cr \
              where cr.oid in (select relid from pg_partition_tree('stream_live_parent')) \
              order by cr.relname",
        ),
        vec![
            vec![Value::Text("stream_live_child".into())],
            vec![Value::Text("stream_live_parent".into())],
        ]
    );
}

