#[test]
fn repeatable_read_update_conflict_errors() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut reader = Session::new(1);
    let mut writer = Session::new(2);

    db.execute(
        10,
        "create table rr_update_conflict (id int4 not null, v int4 not null)",
    )
    .unwrap();
    db.execute(10, "insert into rr_update_conflict values (1, 10)")
        .unwrap();

    reader
        .execute(&db, "begin isolation level repeatable read")
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut reader,
            &db,
            "select v from rr_update_conflict where id = 1"
        ),
        vec![vec![Value::Int32(10)]]
    );

    writer.execute(&db, "begin").unwrap();
    writer
        .execute(&db, "update rr_update_conflict set v = 20 where id = 1")
        .unwrap();
    writer.execute(&db, "commit").unwrap();

    let err = reader
        .execute(&db, "update rr_update_conflict set v = 30 where id = 1")
        .unwrap_err();
    assert_sqlstate(err, "40001", "concurrent update");
    reader.execute(&db, "rollback").unwrap();
}

#[test]
fn repeatable_read_delete_conflict_errors() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut reader = Session::new(1);
    let mut writer = Session::new(2);

    db.execute(10, "create table rr_delete_conflict (id int4 not null)")
        .unwrap();
    db.execute(10, "insert into rr_delete_conflict values (1)")
        .unwrap();

    reader
        .execute(&db, "begin isolation level repeatable read")
        .unwrap();
    assert_eq!(
        session_query_rows(&mut reader, &db, "select count(*) from rr_delete_conflict"),
        vec![vec![Value::Int64(1)]]
    );

    writer.execute(&db, "begin").unwrap();
    writer
        .execute(&db, "delete from rr_delete_conflict where id = 1")
        .unwrap();
    writer.execute(&db, "commit").unwrap();

    let err = reader
        .execute(&db, "delete from rr_delete_conflict where id = 1")
        .unwrap_err();
    assert_sqlstate(err, "40001", "concurrent delete");
    reader.execute(&db, "rollback").unwrap();
}

#[test]
fn txid_status_reports_recent_transaction_states() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session_query_rows(&mut session, &db, "select txid_current()");

    session.execute(&db, "begin").unwrap();
    let committed = match &session_query_rows(&mut session, &db, "select txid_current()")[..] {
        [row] => match &row[..] {
            [Value::Xid8(txid)] => *txid,
            other => panic!("expected committed txid row, got {other:?}"),
        },
        other => panic!("expected committed txid result, got {other:?}"),
    };
    session.execute(&db, "commit").unwrap();

    session.execute(&db, "begin").unwrap();
    let rolled_back = match &session_query_rows(&mut session, &db, "select txid_current()")[..] {
        [row] => match &row[..] {
            [Value::Xid8(txid)] => *txid,
            other => panic!("expected rolled back txid row, got {other:?}"),
        },
        other => panic!("expected rolled back txid result, got {other:?}"),
    };
    session.execute(&db, "rollback").unwrap();

    session.execute(&db, "begin").unwrap();
    let in_progress = match &session_query_rows(&mut session, &db, "select txid_current()")[..] {
        [row] => match &row[..] {
            [Value::Xid8(txid)] => *txid,
            other => panic!("expected in-progress txid row, got {other:?}"),
        },
        other => panic!("expected in-progress txid result, got {other:?}"),
    };

    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            &format!(
                "select txid_status({committed}), txid_status({rolled_back}), \
                        txid_status({in_progress}), txid_status(1), \
                        txid_status(2), txid_status(3)"
            ),
        ),
        vec![vec![
            Value::Text("committed".into()),
            Value::Text("aborted".into()),
            Value::Text("in progress".into()),
            Value::Text("committed".into()),
            Value::Text("committed".into()),
            Value::Null,
        ]]
    );

    let err = session
        .execute(&db, &format!("select txid_status({})", in_progress + 10000))
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::DetailedError {
            sqlstate: "22023",
            ..
        }
    ));

    session.execute(&db, "commit").unwrap();
}

