#[test]
fn recursive_cte_search_cycle_clauses_parse_and_validate_names() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    let err = session
        .execute(
            &db,
            "with recursive g(f, t) as (
                select 1, 2
                union all
                select f + 1, t + 1 from g
            ) search depth first by missing set seq
            select * from g",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "search column \"missing\" not in WITH query column list"
    ));

    let err = session
        .execute(
            &db,
            "with recursive g(f, t) as (
                select 1, 2
                union all
                select f + 1, t + 1 from g
            ) cycle f set t using path
            select * from g",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "cycle mark column name \"t\" already used in WITH query column list"
    ));

    let err = session
        .execute(
            &db,
            "with recursive g(f, t) as (
                select 1, 2
                union all
                select f + 1, t + 1 from g
            ) cycle f set is_cycle to true default 55 using path
            select * from g",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "CYCLE types boolean and integer cannot be matched"
    ));

    let err = session
        .execute(
            &db,
            "with recursive g(f, t) as (
                select 1, 2
                union all
                select f + 1, t + 1 from g
            ) cycle f set is_cycle to point '(1,1)' default point '(0,0)' using path
            select * from g",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "could not identify an equality operator for type point"
    ));

    let err = session
        .execute(
            &db,
            "with recursive x(col) as (
                select 1
                union
                (with x as (select * from x)
                 select * from x)
            ) search depth first by col set seq
            select * from x",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "with a SEARCH or CYCLE clause, the recursive reference to WITH query \"x\" must be at the top level of its right-hand SELECT"
    ));

    let err = session
        .execute(
            &db,
            "with recursive g(n) as (
                select 1
                union all
                select 2
                union all
                select n + 1 from g
            ) search depth first by n set seq
            select * from g",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "with a SEARCH or CYCLE clause, the left side of the UNION must be a SELECT"
    ));

    let err = session
        .execute(
            &db,
            "with recursive g(n) as (
                select 1
                union all
                (select 2
                 union all
                 select n + 1 from g)
            ) search depth first by n set seq
            select * from g",
        )
        .unwrap_err();
    assert!(matches!(
        exec_parse_error(&err),
        Some(ParseError::FeatureNotSupportedMessage(message))
            if message == "with a SEARCH or CYCLE clause, the right side of the UNION must be a SELECT"
    ));
}

