#[test]
fn ephemeral_database_rolls_back_aborted_transaction() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(&db, "create table items (id int)")
        .expect("create table");
    session.execute(&db, "begin").expect("begin");
    session
        .execute(&db, "insert into items values (1)")
        .expect("insert row");
    session.execute(&db, "rollback").expect("rollback");

    let result = session
        .execute(&db, "select id from items")
        .expect("select after rollback");
    let StatementResult::Query { rows, .. } = result else {
        panic!("expected query result");
    };
    assert!(rows.is_empty(), "rolled back row should not be visible");
}

fn query_rows(db: &Database, client_id: u32, sql: &str) -> Vec<Vec<Value>> {
    match db.execute(client_id, sql).unwrap() {
        StatementResult::Query { rows, .. } => rows,
        other => panic!("expected query result, got {:?}", other),
    }
}

fn return_rule_oid_for_relation(db: &Database, relname: &str) -> u32 {
    let catalog = db.catalog.read();
    let catcache = catalog.catcache().unwrap();
    let relation_oid = catcache
        .class_rows()
        .into_iter()
        .find(|row| row.relname == relname)
        .map(|row| row.oid)
        .unwrap_or_else(|| panic!("missing relation {relname}"));
    catcache
        .rewrite_rows()
        .into_iter()
        .find(|row| row.ev_class == relation_oid && row.rulename == "_RETURN")
        .map(|row| row.oid)
        .unwrap_or_else(|| panic!("missing _RETURN rule for {relname}"))
}

#[test]
fn pg_lsn_wal_filename_offset_helpers_match_segment_boundaries() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let segment_size = crate::backend::access::transam::xlog::WAL_SEG_SIZE_BYTES;

    assert_eq!(
        query_rows(
            &db,
            1,
            &format!(
                "select segment_number, file_offset \
                 from pg_walfile_name_offset('0/0'::pg_lsn + {segment_size}), \
                      pg_split_walfile_name(file_name)"
            )
        ),
        vec![vec![
            Value::Numeric(NumericValue::from_i64(1)),
            Value::Int32(0),
        ]]
    );

    assert_eq!(
        query_rows(
            &db,
            1,
            &format!(
                "select segment_number, file_offset \
                 from pg_walfile_name_offset('0/0'::pg_lsn + {segment_size} + 1), \
                      pg_split_walfile_name(file_name)"
            )
        ),
        vec![vec![
            Value::Numeric(NumericValue::from_i64(1)),
            Value::Int32(1),
        ]]
    );

    assert_eq!(
        query_rows(
            &db,
            1,
            &format!(
                "select segment_number, file_offset = {segment_size} - 1 \
                 from pg_walfile_name_offset('0/0'::pg_lsn + {segment_size} - 1), \
                      pg_split_walfile_name(file_name)"
            )
        ),
        vec![vec![
            Value::Numeric(NumericValue::from_i64(0)),
            Value::Bool(true)
        ]]
    );
}

