#[test]
fn materialized_view_set_schema_refresh_concurrently_and_drop_cascade() {
    let db = Database::open_ephemeral(64).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table mv_reg_base(id int4 primary key, amount int4)",
        )
        .unwrap();
    session
        .execute(&db, "insert into mv_reg_base values (1, 10), (2, 20)")
        .unwrap();
    session.execute(&db, "create schema mv_reg_schema").unwrap();
    session
        .execute(
            &db,
            "create materialized view mv_reg_mv as select id, amount from mv_reg_base",
        )
        .unwrap();
    session
        .execute(
            &db,
            "alter materialized view mv_reg_mv set schema mv_reg_schema",
        )
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select n.nspname from pg_class c join pg_namespace n on n.oid = c.relnamespace \
             where c.relname = 'mv_reg_mv'",
        ),
        vec![vec![Value::Text("mv_reg_schema".into())]]
    );

    session
        .execute(
            &db,
            "create unique index mv_reg_mv_id on mv_reg_schema.mv_reg_mv(id)",
        )
        .unwrap();
    session
        .execute(&db, "insert into mv_reg_base values (3, 30)")
        .unwrap();
    session
        .execute(
            &db,
            "refresh materialized view concurrently mv_reg_schema.mv_reg_mv",
        )
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select id, amount from mv_reg_schema.mv_reg_mv order by id",
        ),
        vec![
            vec![Value::Int32(1), Value::Int32(10)],
            vec![Value::Int32(2), Value::Int32(20)],
            vec![Value::Int32(3), Value::Int32(30)],
        ]
    );

    session
        .execute(
            &db,
            "create materialized view mv_reg_bad as select amount from mv_reg_base",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create unique index mv_reg_bad_pred on mv_reg_bad(amount) where amount < 0",
        )
        .unwrap();
    let refresh_err = session
        .execute(&db, "refresh materialized view concurrently mv_reg_bad")
        .unwrap_err();
    assert!(matches!(
        refresh_err,
        ExecError::DetailedError {
            message,
            hint: Some(hint),
            ..
        } if message == "cannot refresh materialized view \"public.mv_reg_bad\" concurrently"
            && hint == "Create a unique index with no WHERE clause on one or more columns of the materialized view."
    ));

    session
        .execute(
            &db,
            "create function mv_reg_drop_idx_fn() returns bool language plpgsql as $$
             begin
               execute 'drop index if exists mv_reg_drop_idx_i';
               return true;
             end $$",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create materialized view mv_reg_drop_idx as \
             select 1 as i where mv_reg_drop_idx_fn()",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create unique index mv_reg_drop_idx_i on mv_reg_drop_idx(i)",
        )
        .unwrap();
    let dropped_index_refresh_err = session
        .execute(
            &db,
            "refresh materialized view concurrently mv_reg_drop_idx",
        )
        .unwrap_err();
    assert!(matches!(
        dropped_index_refresh_err,
        ExecError::DetailedError { message, .. }
            if message == "could not find suitable unique index on materialized view \"mv_reg_drop_idx\""
    ));

    session
        .execute(&db, "create table mv_reg_dups(a int4, b int4)")
        .unwrap();
    session
        .execute(&db, "insert into mv_reg_dups values (1, 10)")
        .unwrap();
    session
        .execute(
            &db,
            "create materialized view mv_reg_dups_mv as select * from mv_reg_dups",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create unique index mv_reg_dups_mv_a_idx on mv_reg_dups_mv(a)",
        )
        .unwrap();
    session
        .execute(&db, "insert into mv_reg_dups values (1, 10)")
        .unwrap();
    let refresh_dup_err = session
        .execute(&db, "refresh materialized view mv_reg_dups_mv")
        .unwrap_err();
    assert!(matches!(
        refresh_dup_err,
        ExecError::DetailedError {
            message,
            detail: Some(detail),
            ..
        } if message == "could not create unique index \"mv_reg_dups_mv_a_idx\""
            && detail == "Key (a)=(1) is duplicated."
    ));
    let refresh_concurrent_dup_err = session
        .execute(&db, "refresh materialized view concurrently mv_reg_dups_mv")
        .unwrap_err();
    assert!(matches!(
        refresh_concurrent_dup_err,
        ExecError::DetailedError {
            message,
            detail: Some(detail),
            ..
        } if message == "new data for materialized view \"mv_reg_dups_mv\" contains duplicate rows without any null columns"
            && detail == "Row: (1,10)"
    ));

    session
        .execute(&db, "create view mv_reg_v as select * from mv_reg_base")
        .unwrap();
    session
        .execute(
            &db,
            "create materialized view mv_reg_dep_mv as select * from mv_reg_v",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create view mv_reg_dep_v as select * from mv_reg_dep_mv",
        )
        .unwrap();
    let drop_restrict_err = session.execute(&db, "drop view mv_reg_v").unwrap_err();
    match drop_restrict_err {
        ExecError::DetailedError {
            detail: Some(detail),
            ..
        } => {
            assert!(
                detail.contains("materialized view mv_reg_dep_mv depends on view mv_reg_v")
                    && detail
                        .contains("view mv_reg_dep_v depends on materialized view mv_reg_dep_mv"),
                "{detail}"
            );
        }
        other => panic!("expected dependency detail, got {other:?}"),
    }
    session.execute(&db, "drop view mv_reg_v cascade").unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from pg_class where relname in \
             ('mv_reg_v', 'mv_reg_dep_mv', 'mv_reg_dep_v')",
        ),
        vec![vec![Value::Int64(0)]]
    );
}

#[test]
fn materialized_view_refresh_uses_security_restricted_operation_guards() {
    let db = Database::open_ephemeral(64).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create function mv_action() returns bool language sql as \
             'declare c cursor with hold for select 1; select true'",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create materialized view sro_mv as select mv_action() with no data",
        )
        .unwrap();
    let cursor_err = session
        .execute(&db, "refresh materialized view sro_mv")
        .unwrap_err();
    assert!(matches!(
        cursor_err,
        ExecError::WithContext { source, .. }
            if matches!(
                *source,
                ExecError::DetailedError { ref message, sqlstate: "0A000", .. }
                    if message == "cannot create a cursor WITH HOLD within security-restricted operation"
            )
    ));

    session
        .execute(&db, "create table sro_trojan_table(id int4)")
        .unwrap();
    session
        .execute(
            &db,
            "create function sro_trojan() returns trigger language plpgsql as \
             'begin return null; end'",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create constraint trigger t after insert on sro_trojan_table \
             initially deferred for each row execute procedure sro_trojan()",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create or replace function mv_action() returns bool language sql as \
             'insert into sro_trojan_table values (1); select true'",
        )
        .unwrap();
    let deferred_err = session
        .execute(&db, "refresh materialized view sro_mv")
        .unwrap_err();
    assert!(matches!(
        deferred_err,
        ExecError::WithContext { source, .. }
            if matches!(
                *source,
                ExecError::DetailedError { ref message, sqlstate: "0A000", .. }
                    if message == "cannot fire deferred trigger within security-restricted operation"
            )
    ));

    session.execute(&db, "begin").unwrap();
    session
        .execute(&db, "set constraints all immediate")
        .unwrap();
    session
        .execute(&db, "refresh materialized view sro_mv")
        .unwrap();
    session.execute(&db, "commit").unwrap();

    session.execute(&db, "create role sro_owner").unwrap();
    session.execute(&db, "create role sro_target").unwrap();
    session
        .execute(&db, "set session authorization sro_owner")
        .unwrap();
    session
        .execute(&db, "create table sro_grant_table(id int4)")
        .unwrap();
    session
        .execute(
            &db,
            "create function sro_unwanted_grant() returns void language sql as \
             'grant sro_target to sro_owner'",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create function sro_grant_trigger() returns trigger language plpgsql as \
             'begin perform sro_unwanted_grant(); return null; end'",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create constraint trigger sro_grant_t after insert on sro_grant_table \
             initially immediate for each row execute procedure sro_grant_trigger()",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create function sro_grant_action() returns bool language sql as \
             'insert into sro_grant_table values (1); select true'",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create materialized view sro_grant_mv as select sro_grant_action() with no data",
        )
        .unwrap();
    let grant_err = session
        .execute(&db, "refresh materialized view sro_grant_mv")
        .unwrap_err();
    assert!(matches!(
        exec_error_detailed_message_sqlstate(&grant_err),
        Some((message, "42501")) if message == "permission denied to grant role \"sro_target\""
    ));
    session.execute(&db, "reset session authorization").unwrap();

    session
        .execute(
            &db,
            "create function sro_one(int4) returns int4 immutable language sql as 'select $1'",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create materialized view sro_index_mv as select 1 as c",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create unique index sro_index_mv_idx on sro_index_mv(c) where sro_one(1) > 0",
        )
        .unwrap();
    session
        .execute(&db, "refresh materialized view concurrently sro_index_mv")
        .unwrap();
}

#[test]
fn sql_cursor_fetch_move_close_and_cleanup() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);
    session
        .execute(&db, "create table cursor_items (id int4)")
        .unwrap();
    session
        .execute(&db, "insert into cursor_items values (1), (2), (3)")
        .unwrap();

    session.execute(&db, "begin").unwrap();
    session
        .execute(
            &db,
            "declare c scroll cursor for select id from cursor_items order by id",
        )
        .unwrap();

    let cursors = session.cursor_view_rows();
    assert_eq!(cursors.len(), 1);
    assert_eq!(cursors[0].name, "c");
    assert!(cursors[0].is_scrollable);

    assert_eq!(
        session_query_rows(&mut session, &db, "fetch forward 2 from c"),
        vec![vec![Value::Int32(1)], vec![Value::Int32(2)]]
    );
    assert_eq!(
        session.execute(&db, "move forward from c").unwrap(),
        StatementResult::AffectedRows(1)
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "fetch prior from c"),
        vec![vec![Value::Int32(2)]]
    );

    session.execute(&db, "close c").unwrap();
    assert!(session.cursor_view_rows().is_empty());
    session.execute(&db, "commit").unwrap();
}

#[test]
fn sql_cursor_fetch_first_with_ties_uses_limit_cursor_path() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);
    session
        .execute(&db, "create table cursor_ties (k int4, v int4)")
        .unwrap();
    session
        .execute(
            &db,
            "insert into cursor_ties values (1, 10), (1, 20), (2, 30)",
        )
        .unwrap();

    session.execute(&db, "begin").unwrap();
    session
        .execute(
            &db,
            "declare c cursor for select k, v from cursor_ties order by k fetch first 2 rows with ties",
        )
        .unwrap();

    assert_eq!(
        session_query_rows(&mut session, &db, "fetch all from c"),
        vec![
            vec![Value::Int32(1), Value::Int32(10)],
            vec![Value::Int32(1), Value::Int32(20)]
        ]
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "fetch 1 from c"),
        Vec::<Vec<Value>>::new()
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "fetch backward 1 from c"),
        vec![vec![Value::Int32(1), Value::Int32(20)]]
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "fetch backward 1 from c"),
        vec![vec![Value::Int32(1), Value::Int32(10)]]
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "fetch all from c"),
        vec![vec![Value::Int32(1), Value::Int32(20)]]
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "fetch backward all from c"),
        vec![
            vec![Value::Int32(1), Value::Int32(20)],
            vec![Value::Int32(1), Value::Int32(10)]
        ]
    );
    session.execute(&db, "rollback").unwrap();
}

#[test]
fn update_where_current_of_uses_cursor_tuple() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create table current_of_items (id int4, label text)")
        .unwrap();
    session
        .execute(
            &db,
            "insert into current_of_items values (1, 'one'), (2, 'two')",
        )
        .unwrap();
    session.execute(&db, "begin").unwrap();
    session
        .execute(
            &db,
            "declare c cursor for select * from current_of_items order by id",
        )
        .unwrap();
    session.execute(&db, "fetch next from c").unwrap();

    match session
        .execute(
            &db,
            "update current_of_items set label = 'uno' where current of c returning id, label",
        )
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int32(1), Value::Text("uno".into())]]);
        }
        other => panic!("expected returning rows, got {other:?}"),
    }
    session.execute(&db, "commit").unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select id, label from current_of_items order by id",
        ),
        vec![
            vec![Value::Int32(1), Value::Text("uno".into())],
            vec![Value::Int32(2), Value::Text("two".into())],
        ]
    );
}

