#[test]
fn alter_generated_expression_recurses_partition_tree() {
    let base = temp_dir("alter_generated_expr_partition_tree");
    let db = Database::open_with_options(&base, DatabaseOpenOptions::new(16)).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table gparent_expr (
                f1 date not null,
                f2 int8,
                f3 int8 generated always as (f2 * 2) stored
            ) partition by range (f1)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table gchild_expr partition of gparent_expr
             (f3 with options generated always as (f2 * 10) stored)
             for values from ('2016-07-01') to ('2016-08-01')",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table gchild_expr2 partition of gparent_expr
             for values from ('2016-08-01') to ('2016-09-01')",
        )
        .unwrap();
    session
        .execute(
            &db,
            "insert into gparent_expr (f1, f2)
             values ('2016-07-15', 2), ('2016-08-15', 3)",
        )
        .unwrap();

    session
        .execute(
            &db,
            "alter table only gparent_expr alter column f3 set expression as (f2 * 4)",
        )
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select c.relname, pg_get_expr(d.adbin, d.adrelid)
               from pg_attrdef d
               join pg_class c on c.oid = d.adrelid
              where c.relname in ('gparent_expr', 'gchild_expr', 'gchild_expr2')
              order by c.relname",
        ),
        vec![
            vec![
                Value::Text("gchild_expr".into()),
                Value::Text("f2 * 10::bigint".into())
            ],
            vec![
                Value::Text("gchild_expr2".into()),
                Value::Text("f2 * 2::bigint".into())
            ],
            vec![
                Value::Text("gparent_expr".into()),
                Value::Text("f2 * 4::bigint".into())
            ],
        ]
    );

    session
        .execute(
            &db,
            "alter table gparent_expr alter column f3 set expression as (f2 * 5)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "insert into gparent_expr (f1, f2)
             values ('2016-07-16', 4), ('2016-08-16', 5)",
        )
        .unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select c.relname, p.f2, p.f3
               from gparent_expr p
               join pg_class c on c.oid = p.tableoid
              order by c.relname, p.f2",
        ),
        vec![
            vec![
                Value::Text("gchild_expr".into()),
                Value::Int64(2),
                Value::Int64(10),
            ],
            vec![
                Value::Text("gchild_expr".into()),
                Value::Int64(4),
                Value::Int64(20),
            ],
            vec![
                Value::Text("gchild_expr2".into()),
                Value::Int64(3),
                Value::Int64(15),
            ],
            vec![
                Value::Text("gchild_expr2".into()),
                Value::Int64(5),
                Value::Int64(25),
            ],
        ]
    );
}

#[test]
fn alter_table_add_check_reconciles_existing_partition_constraint() {
    let dir = temp_dir("alter_partition_check_reconcile");
    let db = Database::open(&dir, 128).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table parted (
                a text default 'a',
                b int4
            ) partition by list (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table part_b partition of parted
             (constraint check_b check (b >= 0))
             for values in ('b')",
        )
        .unwrap();
    session
        .execute(
            &db,
            "alter table parted add constraint check_b check (b >= 0)",
        )
        .unwrap();

    let rows = session_query_rows(
        &mut session,
        &db,
        "select c.relname, con.conname, con.conparentid <> 0, con.conislocal, con.coninhcount
         from pg_constraint con
         join pg_class c on c.oid = con.conrelid
         where con.conname = 'check_b'
         order by c.relname",
    );
    assert_eq!(
        rows,
        vec![
            vec![
                Value::Text("part_b".into()),
                Value::Text("check_b".into()),
                Value::Bool(true),
                Value::Bool(true),
                Value::Int16(1),
            ],
            vec![
                Value::Text("parted".into()),
                Value::Text("check_b".into()),
                Value::Bool(false),
                Value::Bool(true),
                Value::Int16(0),
            ],
        ]
    );

    match session.execute(&db, "insert into parted values ('b', -1)") {
        Err(ExecError::CheckViolation {
            relation,
            constraint,
            ..
        }) if relation == "part_b" && constraint == "check_b" => {}
        other => panic!("expected reconciled inherited check violation, got {other:?}"),
    }
}

