#[test]
fn create_index_on_partitioned_table_builds_index_tree() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table idxpart (a int4, b int4) partition by range (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart1 partition of idxpart for values from (0) to (10)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart2 partition of idxpart for values from (10) to (20) partition by range (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart2a partition of idxpart2 for values from (10) to (15)",
        )
        .unwrap();

    session.execute(&db, "create index on idxpart(a)").unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select relname, relkind::text, relispartition, relhassubclass \
               from pg_class \
              where relname in ('idxpart_a_idx', 'idxpart1_a_idx', 'idxpart2_a_idx', 'idxpart2a_a_idx') \
              order by relname",
        ),
        vec![
            vec![
                Value::Text("idxpart1_a_idx".into()),
                Value::Text("i".into()),
                Value::Bool(true),
                Value::Bool(false),
            ],
            vec![
                Value::Text("idxpart2_a_idx".into()),
                Value::Text("I".into()),
                Value::Bool(true),
                Value::Bool(true),
            ],
            vec![
                Value::Text("idxpart2a_a_idx".into()),
                Value::Text("i".into()),
                Value::Bool(true),
                Value::Bool(false),
            ],
            vec![
                Value::Text("idxpart_a_idx".into()),
                Value::Text("I".into()),
                Value::Bool(false),
                Value::Bool(true),
            ],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select relname, relispartition \
               from pg_class \
              where relname in ('idxpart_a_idx', 'idxpart1_a_idx', 'idxpart2_a_idx', 'idxpart2a_a_idx') \
              order by relname",
        ),
        vec![
            vec![Value::Text("idxpart1_a_idx".into()), Value::Bool(true)],
            vec![Value::Text("idxpart2_a_idx".into()), Value::Bool(true)],
            vec![Value::Text("idxpart2a_a_idx".into()), Value::Bool(true)],
            vec![Value::Text("idxpart_a_idx".into()), Value::Bool(false)],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select child.relname, parent.relname \
               from pg_inherits i \
               join pg_class child on child.oid = i.inhrelid \
               join pg_class parent on parent.oid = i.inhparent \
              where parent.relname in ('idxpart_a_idx', 'idxpart2_a_idx') \
              order by parent.relname, child.relname",
        ),
        vec![
            vec![
                Value::Text("idxpart2a_a_idx".into()),
                Value::Text("idxpart2_a_idx".into()),
            ],
            vec![
                Value::Text("idxpart1_a_idx".into()),
                Value::Text("idxpart_a_idx".into()),
            ],
            vec![
                Value::Text("idxpart2_a_idx".into()),
                Value::Text("idxpart_a_idx".into()),
            ],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_partition_root('idxpart2a_a_idx')::regclass::text",
        ),
        vec![vec![Value::Text("idxpart_a_idx".into())]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select relid::regclass::text, parentrelid::regclass::text, level, isleaf \
               from pg_partition_tree('idxpart_a_idx') \
              order by level, relid::regclass::text",
        ),
        vec![
            vec![
                Value::Text("idxpart_a_idx".into()),
                Value::Null,
                Value::Int32(0),
                Value::Bool(false),
            ],
            vec![
                Value::Text("idxpart1_a_idx".into()),
                Value::Text("idxpart_a_idx".into()),
                Value::Int32(1),
                Value::Bool(true),
            ],
            vec![
                Value::Text("idxpart2_a_idx".into()),
                Value::Text("idxpart_a_idx".into()),
                Value::Int32(1),
                Value::Bool(false),
            ],
            vec![
                Value::Text("idxpart2a_a_idx".into()),
                Value::Text("idxpart2_a_idx".into()),
                Value::Int32(2),
                Value::Bool(true),
            ],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select relid::regclass::text from pg_partition_ancestors('idxpart2a_a_idx')",
        ),
        vec![
            vec![Value::Text("idxpart2a_a_idx".into())],
            vec![Value::Text("idxpart2_a_idx".into())],
            vec![Value::Text("idxpart_a_idx".into())],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select indexdef from pg_indexes where tablename = 'idxpart' and indexname = 'idxpart_a_idx'",
        ),
        vec![vec![Value::Text(
            "CREATE INDEX idxpart_a_idx ON ONLY public.idxpart USING btree (a)".into(),
        )]]
    );

    session
        .execute(&db, "create index idxpart_expr_idx on idxpart ((a+b))")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef(oid) from pg_class where relname = 'idxpart_expr_idx'",
        ),
        vec![vec![Value::Text(
            "CREATE INDEX idxpart_expr_idx ON ONLY public.idxpart USING btree (((a + b)))".into(),
        )]]
    );

    session
        .execute(
            &db,
            "create table idxpart_txt (a text) partition by range (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart_txt1 partition of idxpart_txt for values from ('a') to ('m')",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create index idxpart_txt_idx on idxpart_txt (a collate \"C\" text_pattern_ops)",
        )
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef(oid) from pg_class where relname = 'idxpart_txt_idx'",
        ),
        vec![vec![Value::Text(
            "CREATE INDEX idxpart_txt_idx ON ONLY public.idxpart_txt USING btree (a COLLATE \"C\" text_pattern_ops)"
                .into(),
        )]]
    );
    assert_eq!(
        psql_index_definition(&db, 1, "idxpart_txt", "idxpart_txt_idx"),
        "CREATE INDEX idxpart_txt_idx ON ONLY idxpart_txt USING btree (a COLLATE \"C\" text_pattern_ops)"
    );
}

#[test]
fn create_index_on_partitioned_table_reuses_only_child_without_recursing() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    fn relation_oid(db: &Database, name: &str) -> u32 {
        db.lazy_catalog_lookup(1, None, None)
            .lookup_any_relation(name)
            .unwrap_or_else(|| panic!("expected relation {name}"))
            .relation_oid
    }

    fn index_summary(db: &Database, index_name: &str) -> (u32, Option<u32>, bool) {
        let catalog = db.lazy_catalog_lookup(1, None, None);
        let index_relation = catalog
            .lookup_any_relation(index_name)
            .unwrap_or_else(|| panic!("expected index {index_name}"));
        let index = crate::backend::utils::cache::lsyscache::describe_relation_by_oid(
            db,
            1,
            None,
            index_relation.relation_oid,
        )
        .unwrap_or_else(|| panic!("expected relcache entry for {index_name}"))
        .index
        .unwrap_or_else(|| panic!("expected index metadata for {index_name}"));
        let parent_oid = catalog
            .inheritance_parents(index_relation.relation_oid)
            .first()
            .map(|row| row.inhparent);
        (index.indrelid, parent_oid, index.indisvalid)
    }

    session
        .execute(&db, "create table idxpart (a int4) partition by range (a)")
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart1 partition of idxpart for values from (0) to (100)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart2 partition of idxpart for values from (100) to (1000) partition by range (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart21 partition of idxpart2 for values from (100) to (200)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table idxpart22 partition of idxpart2 for values from (200) to (300)",
        )
        .unwrap();
    session
        .execute(&db, "create index on idxpart22(a)")
        .unwrap();
    session
        .execute(&db, "create index on only idxpart2(a)")
        .unwrap();
    session.execute(&db, "create index on idxpart(a)").unwrap();
    match session.execute(
        &db,
        "alter index idxpart_a_idx attach partition idxpart_a_idx",
    ) {
        Err(ExecError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        }) if message
            == "cannot attach index \"idxpart_a_idx\" as a partition of index \"idxpart_a_idx\""
            && detail
                == "Index \"idxpart_a_idx\" is not an index on any partition of table \"idxpart\"."
            && sqlstate == "42809" => {}
        other => panic!("expected self attach partitioned-index error, got {other:?}"),
    }

    assert_eq!(
        index_summary(&db, "idxpart1_a_idx"),
        (
            relation_oid(&db, "idxpart1"),
            Some(relation_oid(&db, "idxpart_a_idx")),
            true,
        )
    );
    assert_eq!(
        index_summary(&db, "idxpart22_a_idx"),
        (relation_oid(&db, "idxpart22"), None, true)
    );
    assert_eq!(
        index_summary(&db, "idxpart2_a_idx"),
        (
            relation_oid(&db, "idxpart2"),
            Some(relation_oid(&db, "idxpart_a_idx")),
            false,
        )
    );
    assert_eq!(
        index_summary(&db, "idxpart_a_idx"),
        (relation_oid(&db, "idxpart"), None, false)
    );
    assert!(
        query_rows(
            &db,
            1,
            "select relname from pg_class where relname = 'idxpart21_a_idx'",
        )
        .is_empty()
    );

    session
        .execute(
            &db,
            "alter index idxpart2_a_idx attach partition idxpart22_a_idx",
        )
        .unwrap();
    session
        .execute(
            &db,
            "alter index idxpart2_a_idx attach partition idxpart22_a_idx",
        )
        .unwrap();
    assert!(!index_summary(&db, "idxpart2_a_idx").2);
    assert!(!index_summary(&db, "idxpart_a_idx").2);

    session
        .execute(&db, "create index on idxpart21(a)")
        .unwrap();
    session
        .execute(
            &db,
            "alter index idxpart2_a_idx attach partition idxpart21_a_idx",
        )
        .unwrap();
    assert!(index_summary(&db, "idxpart21_a_idx").2);
    assert!(index_summary(&db, "idxpart22_a_idx").2);
    assert!(index_summary(&db, "idxpart2_a_idx").2);
    assert!(index_summary(&db, "idxpart_a_idx").2);
}

