#[test]
fn partitioned_key_coverage_checks_fire_for_root_partition_of_and_attach_partition() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    match session.execute(
        &db,
        "create table miss_root (a int, b int, primary key (a)) partition by range (b)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        })) if message
            == "unique constraint on partitioned table must include all partitioning columns"
            && detail
                == "PRIMARY KEY constraint on table \"miss_root\" lacks column \"b\" which is part of the partition key."
            && sqlstate == "0A000" => {}
        other => panic!("expected root partition-key coverage error, got {other:?}"),
    }

    match session.execute(
        &db,
        "create table miss_excl (a int4range, b int4range, exclude using gist (a with =)) partition by range (a, b)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        })) if message
            == "unique constraint on partitioned table must include all partitioning columns"
            && detail
                == "EXCLUDE constraint on table \"miss_excl\" lacks column \"b\" which is part of the partition key."
            && sqlstate == "0A000" => {}
        other => panic!("expected EXCLUDE partition-key coverage error, got {other:?}"),
    }

    session
        .execute(
            &db,
            "create table include_not_key (a int, b int) partition by list (a)",
        )
        .unwrap();
    match session.execute(
        &db,
        "create unique index on include_not_key (b) include (a)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        })) if message
            == "unique constraint on partitioned table must include all partitioning columns"
            && detail
                == "UNIQUE constraint on table \"include_not_key\" lacks column \"a\" which is part of the partition key."
            && sqlstate == "0A000" => {}
        other => panic!("expected INCLUDE column to not satisfy coverage, got {other:?}"),
    }

    match session.execute(
        &db,
        "create table expr_pk (a int primary key, b int) partition by range ((b + a))",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        })) if message == "unsupported PRIMARY KEY constraint with partition key definition"
            && detail
                == "PRIMARY KEY constraints cannot be used when partition keys include expressions."
            && sqlstate == "0A000" => {}
        other => panic!("expected expression partition-key primary-key error, got {other:?}"),
    }

    session
        .execute(
            &db,
            "create table dup_parent (a int primary key) partition by range (a)",
        )
        .unwrap();
    match session.execute(
        &db,
        "create table dup_parent_child partition of dup_parent (primary key (a)) for values from (0) to (10)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            sqlstate,
            ..
        })) if message == "multiple primary keys for table \"dup_parent_child\" are not allowed"
            && sqlstate == "42P16" => {}
        other => panic!("expected duplicate primary-key rejection, got {other:?}"),
    }

    session
        .execute(
            &db,
            "create table sub_parent (a int, b int, primary key (a)) partition by range (a)",
        )
        .unwrap();
    match session.execute(
        &db,
        "create table sub_parent_child partition of sub_parent for values from (0) to (10) partition by range (b)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        })) if message
            == "unique constraint on partitioned table must include all partitioning columns"
            && detail
                == "PRIMARY KEY constraint on table \"sub_parent_child\" lacks column \"b\" which is part of the partition key."
            && sqlstate == "0A000" => {}
        other => panic!("expected PARTITION OF coverage error, got {other:?}"),
    }

    session
        .execute(
            &db,
            "create table attach_parent_cov (a int, b int, primary key (a)) partition by range (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table attach_child_cov (a int not null, b int) partition by range (b)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table attach_child_cov_1 partition of attach_child_cov for values from (minvalue) to (10)",
        )
        .unwrap();
    match session.execute(
        &db,
        "alter table attach_parent_cov attach partition attach_child_cov for values from (0) to (10)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        })) if message
            == "unique constraint on partitioned table must include all partitioning columns"
            && detail
                == "PRIMARY KEY constraint on table \"attach_child_cov\" lacks column \"b\" which is part of the partition key."
            && sqlstate == "0A000" => {}
        other => panic!("expected ATTACH PARTITION coverage error, got {other:?}"),
    }

    session
        .execute(
            &db,
            "create table attach_parent_cols (a int, b int) partition by list (a)",
        )
        .unwrap();
    session
        .execute(&db, "create table attach_child_extra (b int, c int, a int)")
        .unwrap();
    match session.execute(
        &db,
        "alter table attach_parent_cols attach partition attach_child_extra for values in (1)",
    ) {
        Err(ExecError::DetailedError {
            message,
            detail: Some(detail),
            sqlstate,
            ..
        }) if message
            == "table \"attach_child_extra\" contains column \"c\" not found in parent \"attach_parent_cols\""
            && detail == "The new partition may contain only the columns present in parent."
            && sqlstate == "42804" => {}
        other => panic!("expected ATTACH PARTITION extra-column error, got {other:?}"),
    }
}

#[test]
fn alter_table_add_primary_key_builds_or_attaches_partition_key_trees() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table addpk_empty (a int) partition by range (a)",
        )
        .unwrap();
    session
        .execute(&db, "alter table addpk_empty add primary key (a)")
        .unwrap();

    session
        .execute(
            &db,
            "create table addpk_tree (a int) partition by range (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table addpk_tree_1 partition of addpk_tree for values from (0) to (10)",
        )
        .unwrap();
    session
        .execute(&db, "alter table addpk_tree add primary key (a)")
        .unwrap();

    session
        .execute(
            &db,
            "create table addpk_attach (a int) partition by range (a)",
        )
        .unwrap();
    session
        .execute(&db, "create table addpk_child (a int primary key)")
        .unwrap();
    session
        .execute(
            &db,
            "alter table addpk_attach attach partition addpk_child for values from (0) to (10)",
        )
        .unwrap();
    session
        .execute(&db, "alter table addpk_attach add primary key (a)")
        .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select relname, relkind::text \
               from pg_class \
              where relname in ('addpk_empty_pkey', 'addpk_tree_pkey', 'addpk_attach_pkey') \
              order by relname",
        ),
        vec![
            vec![
                Value::Text("addpk_attach_pkey".into()),
                Value::Text("I".into()),
            ],
            vec![
                Value::Text("addpk_empty_pkey".into()),
                Value::Text("I".into()),
            ],
            vec![
                Value::Text("addpk_tree_pkey".into()),
                Value::Text("I".into()),
            ],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select child.relname, parent.relname \
               from pg_inherits i \
               join pg_class child on child.oid = i.inhrelid \
               join pg_class parent on parent.oid = i.inhparent \
              where parent.relname in ('addpk_tree_pkey', 'addpk_attach_pkey') \
              order by parent.relname, child.relname",
        ),
        vec![
            vec![
                Value::Text("addpk_child_pkey".into()),
                Value::Text("addpk_attach_pkey".into()),
            ],
            vec![
                Value::Text("addpk_tree_1_pkey".into()),
                Value::Text("addpk_tree_pkey".into()),
            ],
        ]
    );
}

#[test]
fn attach_partition_creates_missing_keys_and_fk_to_partitioned_key_stays_rejected() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table attach_parent (a int primary key) partition by range (a)",
        )
        .unwrap();
    session
        .execute(&db, "create table attach_child (a int not null)")
        .unwrap();
    session
        .execute(
            &db,
            "alter table attach_parent attach partition attach_child for values from (0) to (10)",
        )
        .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select child.relname, parent.relname \
               from pg_inherits i \
               join pg_class child on child.oid = i.inhrelid \
               join pg_class parent on parent.oid = i.inhparent \
              where parent.relname = 'attach_parent_pkey'",
        ),
        vec![vec![
            Value::Text("attach_child_pkey".into()),
            Value::Text("attach_parent_pkey".into()),
        ]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select count(*) from pg_constraint \
              where conrelid = 'attach_parent'::regclass \
                and contype::text = 'n'",
        ),
        vec![vec![Value::Int64(1)]]
    );

    session
        .execute(
            &db,
            "create table fk_to_partitioned_parent (a int references attach_parent(a))",
        )
        .unwrap();
    session
        .execute(&db, "insert into attach_parent values (1)")
        .unwrap();
    session
        .execute(&db, "insert into fk_to_partitioned_parent values (1)")
        .unwrap();
    match session.execute(&db, "insert into fk_to_partitioned_parent values (2)") {
        Err(ExecError::ForeignKeyViolation { constraint, .. }) => {
            assert_eq!(constraint, "fk_to_partitioned_parent_a_fkey");
        }
        other => panic!("expected FK-to-partitioned-table violation, got {other:?}"),
    }
}

#[test]
fn partitioned_primary_key_propagates_to_nested_and_attached_partitions() {
    let db = Database::open_ephemeral(32).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table nested_pk_parent (
                id int4 not null,
                bucket int4 not null,
                primary key (id, bucket)
             ) partition by range (bucket)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table nested_pk_mid partition of nested_pk_parent
             for values from (0) to (100) partition by range (bucket)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table nested_pk_leaf partition of nested_pk_mid
             for values from (0) to (50)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table nested_pk_attached (
                id int4 not null,
                bucket int4 not null
             )",
        )
        .unwrap();
    session
        .execute(
            &db,
            "alter table nested_pk_parent attach partition nested_pk_attached
             for values from (100) to (200)",
        )
        .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select c.relname, con.conparentid <> 0, con.conislocal, con.coninhcount::int4
               from pg_constraint con
               join pg_class c on c.oid = con.conrelid
              where c.relname in (
                    'nested_pk_parent',
                    'nested_pk_mid',
                    'nested_pk_leaf',
                    'nested_pk_attached'
                )
                and con.contype::text = 'p'
              order by c.relname",
        ),
        vec![
            vec![
                Value::Text("nested_pk_attached".into()),
                Value::Bool(true),
                Value::Bool(false),
                Value::Int32(1),
            ],
            vec![
                Value::Text("nested_pk_leaf".into()),
                Value::Bool(true),
                Value::Bool(false),
                Value::Int32(1),
            ],
            vec![
                Value::Text("nested_pk_mid".into()),
                Value::Bool(true),
                Value::Bool(false),
                Value::Int32(1),
            ],
            vec![
                Value::Text("nested_pk_parent".into()),
                Value::Bool(false),
                Value::Bool(true),
                Value::Int32(0),
            ],
        ]
    );

    assert_eq!(
        query_rows(
            &db,
            1,
            "select child.relname, parent.relname
               from pg_inherits i
               join pg_class child on child.oid = i.inhrelid
               join pg_class parent on parent.oid = i.inhparent
              where parent.relname in ('nested_pk_parent_pkey', 'nested_pk_mid_pkey')
              order by parent.relname, child.relname",
        ),
        vec![
            vec![
                Value::Text("nested_pk_leaf_pkey".into()),
                Value::Text("nested_pk_mid_pkey".into()),
            ],
            vec![
                Value::Text("nested_pk_attached_pkey".into()),
                Value::Text("nested_pk_parent_pkey".into()),
            ],
            vec![
                Value::Text("nested_pk_mid_pkey".into()),
                Value::Text("nested_pk_parent_pkey".into()),
            ],
        ]
    );
}

