#[test]
fn alter_table_no_inherit_localizes_inherited_check_constraint() {
    let dir = temp_dir("alter_table_no_inherit_check");
    let db = Database::open(&dir, 128).unwrap();

    db.execute(1, "create table ac (aa int)").unwrap();
    db.execute(
        1,
        "alter table ac add constraint ac_check check (aa is not null)",
    )
    .unwrap();
    db.execute(1, "create table bc () inherits (ac)").unwrap();

    assert_eq!(
        int_value(
            &query_rows(
                &db,
                1,
                "select count(*)
                 from pg_inherits i
                 join pg_class c on c.oid = i.inhrelid
                 join pg_class p on p.oid = i.inhparent
                 where c.relname = 'bc' and p.relname = 'ac'",
            )[0][0],
        ),
        1
    );

    db.execute(1, "alter table bc no inherit ac").unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select conname, conislocal, coninhcount
             from pg_constraint c
             join pg_class r on r.oid = c.conrelid
             where r.relname = 'bc'
             order by conname",
        ),
        vec![vec![
            Value::Text("ac_check".into()),
            Value::Bool(true),
            Value::Int16(0),
        ]]
    );
    assert_eq!(
        int_value(
            &query_rows(
                &db,
                1,
                "select count(*)
                 from pg_inherits i
                 join pg_class c on c.oid = i.inhrelid
                 where c.relname = 'bc'",
            )[0][0],
        ),
        0
    );

    match db.execute(1, "insert into bc values (null)") {
        Err(ExecError::CheckViolation {
            relation,
            constraint,
            ..
        }) if relation == "bc" && constraint == "ac_check" => {}
        other => panic!("expected localized inherited check violation, got {other:?}"),
    }

    db.execute(1, "alter table bc drop constraint ac_check")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select conname
             from pg_constraint c
             join pg_class r on r.oid = c.conrelid
             where r.relname = 'bc'",
        ),
        Vec::<Vec<Value>>::new()
    );
}

#[test]
fn alter_table_add_check_merges_inherited_constraint_as_local() {
    let dir = temp_dir("alter_table_add_check_merges_inherited");
    let db = Database::open(&dir, 128).unwrap();

    db.execute(1, "create table p1 (f1 int)").unwrap();
    db.execute(1, "create table c1 () inherits (p1)").unwrap();
    db.execute(1, "alter table p1 add constraint f1_pos check (f1 > 0)")
        .unwrap();
    db.execute(1, "alter table c1 add constraint f1_pos check (f1 > 0)")
        .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select conislocal, coninhcount
             from pg_constraint pgc
             join pg_class c on c.oid = pgc.conrelid
             where c.relname = 'c1' and pgc.conname = 'f1_pos'",
        ),
        vec![vec![Value::Bool(true), Value::Int16(1)]]
    );

    match db.execute(1, "alter table c1 drop constraint f1_pos") {
        Err(ExecError::DetailedError {
            message, sqlstate, ..
        }) => {
            assert_eq!(
                message,
                "cannot drop inherited constraint \"f1_pos\" of relation \"c1\""
            );
            assert_eq!(sqlstate, "42P16");
        }
        other => panic!("expected inherited check drop rejection, got {other:?}"),
    }
}

