#[test]
fn explain_update_accepts_inherited_update_statement() {
    let dir = temp_dir("inheritance_explain_update");
    let db = Database::open(&dir, 128).unwrap();

    db.execute(
        1,
        "create table some_tab (f1 int, f2 int, f3 int, check (f1 < 10) no inherit)",
    )
    .unwrap();
    db.execute(1, "create table some_tab_child () inherits(some_tab)")
        .unwrap();
    db.execute(
        1,
        "insert into some_tab_child select i, i + 1, 0 from generate_series(1, 1000) i",
    )
    .unwrap();
    db.execute(1, "create index on some_tab_child(f1, f2)")
        .unwrap();

    let StatementResult::Query { rows, .. } = db
        .execute(
            1,
            "explain (costs off) update some_tab set f3 = 11 where f1 = 12 and f2 = 13",
        )
        .unwrap()
    else {
        panic!("expected query result");
    };
    let lines = rows
        .into_iter()
        .map(|row| match row.first() {
            Some(Value::Text(text)) => text.to_string(),
            other => panic!("expected explain text row, got {:?}", other),
        })
        .collect::<Vec<_>>();

    assert_eq!(
        lines.first().map(String::as_str),
        Some("Update on some_tab")
    );
    assert!(
        lines.iter().any(|line| {
            line.contains("Index Scan using") && line.contains("on some_tab_child")
        }),
        "expected EXPLAIN UPDATE to show inherited child index scan, got {lines:?}"
    );
    assert!(
        !lines
            .iter()
            .any(|line| line.contains("Seq Scan on some_tab ")),
        "expected parent-local NO INHERIT check to prune parent scan, got {lines:?}"
    );
    assert!(
        lines.iter().any(|line| line.contains("f1 =")
            && line.contains("f2 =")
            && line.contains("12")
            && line.contains("13")),
        "expected EXPLAIN UPDATE to show index quals, got {lines:?}"
    );
}

#[test]
fn explain_verbose_update_where_false_is_accepted() {
    let dir = temp_dir("inheritance_explain_update_false");
    let db = Database::open(&dir, 128).unwrap();

    db.execute(1, "create table some_tab (a int, b int)")
        .unwrap();
    db.execute(1, "create table some_tab_child () inherits (some_tab)")
        .unwrap();
    db.execute(1, "insert into some_tab_child values (1, 2)")
        .unwrap();

    let StatementResult::Query { rows, .. } = db
        .execute(
            1,
            "explain (verbose, costs off) update some_tab set a = a + 1 where false",
        )
        .unwrap()
    else {
        panic!("expected query result");
    };
    let lines = rows
        .into_iter()
        .map(|row| match row.first() {
            Some(Value::Text(text)) => text.to_string(),
            other => panic!("expected explain text row, got {:?}", other),
        })
        .collect::<Vec<_>>();

    assert_eq!(
        lines.first().map(String::as_str),
        Some("Update on public.some_tab")
    );
    assert!(
        lines
            .iter()
            .any(|line| line == "        Output: (some_tab.a + 1), NULL::oid, NULL::tid"),
        "expected EXPLAIN VERBOSE UPDATE to render assignment output, got {lines:?}"
    );
    assert!(
        lines
            .iter()
            .any(|line| line == "        One-Time Filter: false"),
        "expected EXPLAIN VERBOSE UPDATE to show false one-time filter, got {lines:?}"
    );
}

#[test]
fn explain_verbose_update_composite_fields_uses_scan_projection() {
    let dir = temp_dir("explain_update_composite_fields");
    let db = Database::open(&dir, 128).unwrap();

    db.execute(1, "create type explain_comp as (r float8, i float8)")
        .unwrap();
    db.execute(1, "create table explain_comp_tab (d1 explain_comp)")
        .unwrap();

    let lines = explain_lines(
        &db,
        1,
        "(verbose, costs off) update explain_comp_tab set d1.r = (d1).r - 1, d1.i = (d1).i + 1 where (d1).i > 0",
    );

    assert_eq!(
        lines.first().map(String::as_str),
        Some("Update on public.explain_comp_tab")
    );
    assert!(
        lines
            .iter()
            .any(|line| line == "  ->  Seq Scan on public.explain_comp_tab"),
        "expected EXPLAIN VERBOSE UPDATE to fold projection into scan, got {lines:?}"
    );
    assert!(
        lines.iter().any(|line| {
            line == "        Output: ROW(((d1).r - '1'::double precision), ((d1).i + '1'::double precision)), ctid"
        }),
        "expected EXPLAIN VERBOSE UPDATE to render composite-field output, got {lines:?}"
    );
    assert!(
        lines.iter().any(|line| {
            line == "        Filter: ((explain_comp_tab.d1).i > '0'::double precision)"
        }),
        "expected EXPLAIN VERBOSE UPDATE to render composite-field filter, got {lines:?}"
    );
}

