#[test]
fn alter_table_add_column_reads_old_rows_with_null_or_default() {
    let base = temp_dir("alter_table_add_column_reads_old_rows");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table items (id int4 not null)")
        .unwrap();
    db.execute(1, "insert into items values (1), (2)").unwrap();
    db.execute(1, "alter table items add column note text")
        .unwrap();

    assert_eq!(
        query_rows(&db, 1, "select id, note from items order by id"),
        vec![
            vec![Value::Int32(1), Value::Null],
            vec![Value::Int32(2), Value::Null],
        ]
    );

    db.execute(1, "alter table items add column bucket int4 default 3")
        .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select id, note, bucket from items order by id"),
        vec![
            vec![Value::Int32(1), Value::Null, Value::Int32(3)],
            vec![Value::Int32(2), Value::Null, Value::Int32(3)],
        ]
    );

    db.execute(1, "create table random_defaults (id int4)")
        .unwrap();
    db.execute(1, "insert into random_defaults values (1), (2)")
        .unwrap();
    db.execute(
        1,
        "alter table random_defaults add column d float8 default random()",
    )
    .unwrap();
    let random_default_expr = query_rows(
        &db,
        1,
        "select pg_get_expr(adbin, adrelid)
           from pg_attrdef
          where adrelid = 'random_defaults'::regclass",
    );
    match random_default_expr.as_slice() {
        [row] if row.len() == 1 => match &row[0] {
            Value::Text(expr)
                if expr.eq_ignore_ascii_case("random()") || expr.eq_ignore_ascii_case("random") => {
            }
            other => panic!("expected random default expression, got {other:?}"),
        },
        other => panic!("expected one random default expression row, got {other:?}"),
    }
    db.execute(1, "insert into random_defaults (id) values (3)")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select d is not null from random_defaults where id = 3"
        ),
        vec![vec![Value::Bool(true)]]
    );

    db.execute(1, "create table invalid_nn_rewrite (a int4, b int4)")
        .unwrap();
    db.execute(1, "insert into invalid_nn_rewrite values (null, 1), (2, 2)")
        .unwrap();
    db.execute(
        1,
        "alter table invalid_nn_rewrite add constraint nn not null a not valid",
    )
    .unwrap();
    db.execute(
        1,
        "alter table invalid_nn_rewrite add column d float8 default random()",
    )
    .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select a is null, d is not null from invalid_nn_rewrite order by b"
        ),
        vec![
            vec![Value::Bool(true), Value::Bool(true)],
            vec![Value::Bool(false), Value::Bool(true)],
        ]
    );

    db.execute(1, "create table random_not_null (id int4)")
        .unwrap();
    db.execute(1, "insert into random_not_null values (1)")
        .unwrap();
    db.execute(
        1,
        "alter table random_not_null
           add column b float8 not null default random(),
           add primary key(id)",
    )
    .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select b is not null from random_not_null where id = 1"
        ),
        vec![vec![Value::Bool(true)]]
    );
}

#[test]
fn stored_expression_deparse_matches_pg_for_checks_and_defaults() {
    let base = temp_dir("stored_expression_deparse_matches_pg");
    let db = Database::open(&base, 16).unwrap();

    db.execute(
        1,
        "create table deparse_checks (
            d date check (d between '2001-01-01'::date and '2099-12-31'::date),
            a float8 check (a > 10.2)
        )",
    )
    .unwrap();
    db.execute(
        1,
        "create table deparse_defaults (b integer default random()::int)",
    )
    .unwrap();
    db.execute(1, "create sequence deparse_seq").unwrap();
    db.execute(
        1,
        "create table deparse_builtin_defaults (id integer default nextval('deparse_seq'))",
    )
    .unwrap();
    db.execute(
        1,
        "create table deparse_builtin_checks (
            op text[],
            value text[],
            check (cardinality(op) = cardinality(value))
        )",
    )
    .unwrap();
    db.execute(
        1,
        "create table deparse_builtin_ranges (
            a integer,
            r int4range generated always as (int4range(a, a + 5)) stored
        )",
    )
    .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_expr(conbin, conrelid)
               from pg_constraint
              where conrelid = 'deparse_checks'::regclass and conname = 'deparse_checks_d_check'",
        ),
        vec![vec![Value::Text(
            "d >= '01-01-2001'::date AND d <= '12-31-2099'::date".into()
        )]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_constraintdef(oid, true)
               from pg_constraint
              where conrelid = 'deparse_checks'::regclass and conname = 'deparse_checks_d_check'",
        ),
        vec![vec![Value::Text(
            "CHECK (d >= '01-01-2001'::date AND d <= '12-31-2099'::date)".into()
        )]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_expr(adbin, adrelid)
               from pg_attrdef
              where adrelid = 'deparse_defaults'::regclass",
        ),
        vec![vec![Value::Text("random()::integer".into())]]
    );
    let nextval_default_expr = query_rows(
        &db,
        1,
        "select pg_get_expr(adbin, adrelid)
           from pg_attrdef
          where adrelid = 'deparse_builtin_defaults'::regclass",
    );
    let [nextval_default_row] = nextval_default_expr.as_slice() else {
        panic!("unexpected nextval default expression: {nextval_default_expr:?}");
    };
    let [Value::Text(nextval_default_expr)] = nextval_default_row.as_slice() else {
        panic!("unexpected nextval default expression: {nextval_default_expr:?}");
    };
    assert!(
        nextval_default_expr.starts_with("nextval(")
            && nextval_default_expr.contains("::regclass)")
            && !nextval_default_expr.contains("function(")
            && !nextval_default_expr.contains("::regclass)::regclass"),
        "unexpected nextval default expression: {nextval_default_expr}"
    );
    db.execute(1, "insert into deparse_builtin_defaults default values")
        .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select * from deparse_builtin_defaults"),
        vec![vec![Value::Int32(1)]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_expr(adbin, adrelid) not like '%function%'
               from pg_attrdef
              where adrelid = 'deparse_builtin_defaults'::regclass",
        ),
        vec![vec![Value::Bool(true)]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_expr(conbin, conrelid) not like '%function%'
               from pg_constraint
              where conrelid = 'deparse_builtin_checks'::regclass",
        ),
        vec![vec![Value::Bool(true)]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_expr(adbin, adrelid) not like '%function%'
               from pg_attrdef
              where adrelid = 'deparse_builtin_ranges'::regclass",
        ),
        vec![vec![Value::Bool(true)]]
    );
    db.execute(
        1,
        "insert into deparse_builtin_checks values ('{=}'::text[], '{1}'::text[])",
    )
    .unwrap();
    db.execute(1, "insert into deparse_builtin_ranges (a) values (4)")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select check_clause
               from information_schema.check_constraints
              where constraint_name = 'deparse_checks_a_check'",
        ),
        vec![vec![Value::Text("(a > 10.2::double precision)".into())]]
    );

    db.execute(1, "alter table deparse_checks alter column a type numeric")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_constraintdef(oid, true)
               from pg_constraint
              where conrelid = 'deparse_checks'::regclass and conname = 'deparse_checks_a_check'",
        ),
        vec![vec![Value::Text(
            "CHECK (a::double precision > 10.2::double precision)".into()
        )]]
    );
}

