#[test]
fn explain_analyze_json_reports_gin_bitmap_stats() {
    let base = temp_dir("gin_explain_analyze_json");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create table docs (id int4 not null, tags int4[])")
        .unwrap();
    session
        .execute(
            &db,
            "insert into docs values \
             (1, ARRAY[1]::int4[]), \
             (2, ARRAY[1,2]::int4[]), \
             (3, ARRAY[]::int4[])",
        )
        .unwrap();
    session
        .execute(&db, "create index docs_tags_gin on docs using gin (tags)")
        .unwrap();
    session.execute(&db, "set enable_seqscan = off").unwrap();

    let result = session
        .execute(
            &db,
            "explain (analyze, format json) \
             select * from docs where tags @> ARRAY[]::int4[]",
        )
        .unwrap();
    let StatementResult::Query { rows, .. } = result else {
        panic!("expected EXPLAIN query result");
    };
    let Some(json) = rows
        .first()
        .and_then(|row| row.first())
        .and_then(|value| match value {
            Value::Json(json) | Value::Text(json) => Some(json),
            _ => None,
        })
    else {
        panic!("expected JSON EXPLAIN row, got {rows:?}");
    };
    let parsed: serde_json::Value =
        serde_json::from_str(json.as_str()).expect("EXPLAIN JSON must parse");
    assert_eq!(parsed[0]["Plan"]["Actual Rows"].as_f64(), Some(3.0));
    assert_eq!(
        parsed[0]["Plan"]["Rows Removed by Index Recheck"],
        serde_json::json!(0)
    );
    assert_eq!(
        parsed[0]["Plan"]["Plans"][0]["Actual Rows"].as_f64(),
        Some(3.0)
    );
}

#[test]
fn vacuum_preserves_live_temp_rows_after_large_delete() {
    let base = temp_dir("vacuum_temp_large_delete_survivors");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create temp table docs (i int4[], j int4[])")
        .unwrap();
    session
        .execute(
            &db,
            "insert into docs values \
              (null,    null), \
              ('{}',    null), \
              ('{1}',   null), \
              ('{1,2}', null), \
              (null,    '{}'), \
              (null,    '{10}'), \
              ('{1,2}', '{10}'), \
              ('{2}',   '{10}'), \
              ('{1,3}', '{}'), \
              ('{1,1}', '{10}')",
        )
        .unwrap();
    session
        .execute(
            &db,
            "insert into docs select ARRAY[1, g, g/10]::int4[], ARRAY[2, g, g/10]::int4[] \
             from generate_series(1, 20000) g",
        )
        .unwrap();
    session
        .execute(&db, "delete from docs where j @> ARRAY[2]::int4[]")
        .unwrap();
    assert_eq!(
        session_query_rows(&mut session, &db, "select count(*) from docs"),
        vec![vec![Value::Int64(10)]]
    );

    session.execute(&db, "vacuum docs").unwrap();

    assert_eq!(
        session_query_rows(&mut session, &db, "select count(*) from docs"),
        vec![vec![Value::Int64(10)]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from docs where j @> '{}'::int4[]",
        ),
        vec![vec![Value::Int64(6)]]
    );
}

#[test]
fn gin_vacuum_preserves_empty_query_survivors() {
    let base = temp_dir("gin_empty_query_vacuum_survivors");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create temp table docs (i int4[], j int4[])")
        .unwrap();
    session
        .execute(&db, "create index docs_gin_idx on docs using gin (i, j)")
        .unwrap();
    session
        .execute(
            &db,
            "insert into docs values \
              (null,    null), \
              ('{}',    null), \
              ('{1}',   null), \
              ('{1,2}', null), \
              (null,    '{}'), \
              (null,    '{10}'), \
              ('{1,2}', '{10}'), \
              ('{2}',   '{10}'), \
              ('{1,3}', '{}'), \
              ('{1,1}', '{10}')",
        )
        .unwrap();
    session.execute(&db, "set enable_seqscan = off").unwrap();
    let _ = session_query_rows(
        &mut session,
        &db,
        "select * from docs where ARRAY[0]::int4[] <@ i",
    );
    let _ = session_query_rows(
        &mut session,
        &db,
        "select * from docs where ARRAY[0]::int4[] <@ i and '{}'::int4[] <@ j",
    );
    let _ = session_query_rows(&mut session, &db, "select * from docs where i @> '{}'");
    session
        .execute(
            &db,
            "create function explain_query_json(query_sql text) \
             returns table (explain_line json) language plpgsql as $$ \
             begin \
               set enable_seqscan = off; \
               set enable_bitmapscan = on; \
               return query execute 'EXPLAIN (ANALYZE, FORMAT json) ' || query_sql; \
             end; \
             $$",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create function execute_text_query_index(query_sql text) \
             returns setof text language plpgsql as $$ \
             begin \
               set enable_seqscan = off; \
               set enable_bitmapscan = on; \
               return query execute query_sql; \
             end; \
             $$",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create function execute_text_query_heap(query_sql text) \
             returns setof text language plpgsql as $$ \
             begin \
               set enable_seqscan = on; \
               set enable_bitmapscan = off; \
               return query execute query_sql; \
             end; \
             $$",
        )
        .unwrap();
    let _ = session_query_rows(
        &mut session,
        &db,
        "select query, \
                js->0->'Plan'->'Plans'->0->'Actual Rows', \
                js->0->'Plan'->'Rows Removed by Index Recheck', \
                (res_index = res_heap) \
         from \
           (values \
             ($$ i @> '{}' $$), \
             ($$ j @> '{}' $$), \
             ($$ i @> '{}' and j @> '{}' $$), \
             ($$ i @> '{1}' $$), \
             ($$ i @> '{1}' and j @> '{}' $$), \
             ($$ i @> '{1}' and i @> '{}' and j @> '{}' $$), \
             ($$ j @> '{10}' $$), \
             ($$ j @> '{10}' and i @> '{}' $$), \
             ($$ j @> '{10}' and j @> '{}' and i @> '{}' $$), \
             ($$ i @> '{1}' and j @> '{10}' $$) \
           ) q(query), \
           lateral explain_query_json($$select * from docs where $$ || query) js, \
           lateral execute_text_query_index($$select string_agg((i, j)::text, ' ') from docs where $$ || query) res_index, \
           lateral execute_text_query_heap($$select string_agg((i, j)::text, ' ') from docs where $$ || query) res_heap",
    );
    session.execute(&db, "reset enable_seqscan").unwrap();
    session.execute(&db, "reset enable_bitmapscan").unwrap();
    session
        .execute(
            &db,
            "insert into docs select ARRAY[1, g, g/10]::int4[], ARRAY[2, g, g/10]::int4[] \
             from generate_series(1, 20000) g",
        )
        .unwrap();
    session
        .execute(&db, "select gin_clean_pending_list('docs_gin_idx')")
        .unwrap();
    session.execute(&db, "analyze docs").unwrap();

    session.execute(&db, "set enable_seqscan = off").unwrap();
    session.execute(&db, "set enable_bitmapscan = on").unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from docs where j @> ARRAY[50]::int4[]",
        ),
        vec![vec![Value::Int64(11)]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from docs where j @> ARRAY[2]::int4[]",
        ),
        vec![vec![Value::Int64(20000)]]
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from docs where j @> '{}'::int4[]",
        ),
        vec![vec![Value::Int64(20006)]]
    );

    session
        .execute(&db, "delete from docs where j @> ARRAY[2]::int4[]")
        .unwrap();
    session.execute(&db, "vacuum docs").unwrap();

    session.execute(&db, "set enable_seqscan = on").unwrap();
    session.execute(&db, "set enable_bitmapscan = off").unwrap();
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from docs where j @> '{}'::int4[]",
        ),
        vec![vec![Value::Int64(6)]],
        "heap path should retain the six non-null j rows"
    );

    session.execute(&db, "set enable_seqscan = off").unwrap();
    session.execute(&db, "set enable_bitmapscan = on").unwrap();
    let lines = session_explain_lines(
        &mut session,
        &db,
        "select count(*) from docs where j @> '{}'::int4[]",
    );
    assert!(
        lines
            .iter()
            .any(|line| line.contains("Bitmap Heap Scan on docs")),
        "expected Bitmap Heap Scan in EXPLAIN, got {lines:?}"
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select count(*) from docs where j @> '{}'::int4[]",
        ),
        vec![vec![Value::Int64(6)]],
        "GIN bitmap path should retain empty-query survivor TIDs after vacuum"
    );
}

#[test]
fn reopen_brin_index_preserves_pages_per_range_in_catalog() {
    let base = temp_dir("brin_reopen_catalog_options");

    {
        let db = Database::open(&base, 16).unwrap();
        db.execute(1, "create table items (a int4 not null)")
            .unwrap();
        db.execute(
            1,
            "create index items_a_brin on items using brin (a) with (pages_per_range = 32)",
        )
        .unwrap();

        let catalog = db.catalog.read().catalog_snapshot().unwrap();
        let index = catalog.get("items_a_brin").unwrap();
        assert_eq!(
            index
                .index_meta
                .as_ref()
                .and_then(|meta| meta.brin_options.as_ref())
                .map(|options| options.pages_per_range),
            Some(32)
        );
    }

    let reopened = Database::open(&base, 16).unwrap();
    let catalog = reopened.catalog.read().catalog_snapshot().unwrap();
    let index = catalog.get("items_a_brin").unwrap();
    assert_eq!(
        index
            .index_meta
            .as_ref()
            .and_then(|meta| meta.brin_options.as_ref())
            .map(|options| options.pages_per_range),
        Some(32)
    );
}

#[test]
fn create_gist_box_index_supports_knn_order_by() {
    let base = temp_dir("gist_box_knn_order");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table boxes (id int4 not null, b box)")
        .unwrap();
    db.execute(
        1,
        "insert into boxes values \
         (1, '(0,0),(1,1)'::box), \
         (2, '(5,5),(6,6)'::box), \
         (3, '(10,10),(12,12)'::box), \
         (4, '(7,7),(8,8)'::box)",
    )
    .unwrap();

    let sql = "select id from boxes \
               order by b <-> '(5.2,5.2),(5.2,5.2)'::box \
               limit 3";
    let expected = query_rows(&db, 1, sql);
    assert_eq!(
        expected,
        vec![
            vec![Value::Int32(2)],
            vec![Value::Int32(4)],
            vec![Value::Int32(1)],
        ]
    );

    db.execute(1, "create index boxes_b_gist on boxes using gist (b)")
        .unwrap();

    assert_explain_uses_index(&db, 1, sql, "boxes_b_gist");
    assert_eq!(query_rows(&db, 1, sql), expected);
}

#[test]
fn create_spgist_text_index_supports_pattern_and_prefix_ops() {
    let base = temp_dir("spgist_text_pattern_prefix");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table texts (id int4 not null, t text)")
        .unwrap();
    db.execute(
        1,
        "insert into texts values \
         (1, 'alpha'), \
         (2, 'beta'), \
         (3, 'delta'), \
         (4, 'omega'), \
         (5, 'word'), \
         (6, 'world')",
    )
    .unwrap();
    db.execute(1, "create index texts_t_spgist on texts using spgist (t)")
        .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select indclass \
             from pg_index \
             where indexrelid = (select oid from pg_class where relname = 'texts_t_spgist')",
        ),
        vec![vec![Value::Text(
            crate::include::catalog::TEXT_SPGIST_OPCLASS_OID
                .to_string()
                .into()
        )]]
    );

    let lt_sql = "select id from texts where t ~<~ 'delta' order by id";
    assert_explain_uses_index(&db, 1, lt_sql, "texts_t_spgist");
    assert_eq!(
        query_rows(&db, 1, lt_sql),
        vec![vec![Value::Int32(1)], vec![Value::Int32(2)]]
    );

    assert_eq!(
        query_rows(
            &db,
            1,
            "select id from texts where t ~<=~ 'beta' order by id",
        ),
        vec![vec![Value::Int32(1)], vec![Value::Int32(2)]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select id from texts where t ~>=~ 'word' order by id",
        ),
        vec![vec![Value::Int32(5)], vec![Value::Int32(6)]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select id from texts where t ~>~ 'word' order by id",
        ),
        vec![vec![Value::Int32(6)]]
    );

    let prefix_sql = "select id from texts where t ^@ 'wo' order by id";
    assert_explain_uses_index(&db, 1, prefix_sql, "texts_t_spgist");
    assert_eq!(
        query_rows(&db, 1, prefix_sql),
        vec![vec![Value::Int32(5)], vec![Value::Int32(6)]]
    );

    let function_sql = "select id from texts where starts_with(t, 'wo') order by id";
    assert_explain_uses_index(&db, 1, function_sql, "texts_t_spgist");
    assert_eq!(
        query_rows(&db, 1, function_sql),
        vec![vec![Value::Int32(5)], vec![Value::Int32(6)]]
    );
}

#[test]
fn create_spgist_rejects_multicolumn_indexes() {
    let base = temp_dir("spgist_reject_multicolumn");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table boxes (a box, b box)").unwrap();

    match db.execute(
        1,
        "create index boxes_ab_spgist on boxes using spgist (a, b)",
    ) {
        Err(ExecError::DetailedError {
            message, sqlstate, ..
        }) => {
            assert_eq!(
                message,
                "access method \"spgist\" does not support multicolumn indexes"
            );
            assert_eq!(sqlstate, "0A000");
        }
        other => panic!("expected multicolumn SP-GiST rejection, got {:?}", other),
    }
}

