#[test]
fn alter_table_add_exclusion_constraint_accepts_expression_key() {
    let base = temp_dir("alter_add_exclusion_expression");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table add_excl_expr(a int primary key)")
        .unwrap();
    db.execute(
        1,
        "alter table add_excl_expr add constraint add_excl_expr_excl exclude ((1) with =)",
    )
    .unwrap();

    let lookup = db.lazy_catalog_lookup(1, None, None);
    let relation = lookup.lookup_any_relation("add_excl_expr").unwrap();
    let constraint = lookup
        .constraint_rows_for_relation(relation.relation_oid)
        .into_iter()
        .find(|row| row.conname == "add_excl_expr_excl")
        .unwrap();
    assert_eq!(
        constraint.contype,
        crate::include::catalog::CONSTRAINT_EXCLUSION
    );
    assert_eq!(constraint.conkey.as_deref(), Some(&[0][..]));
    assert_eq!(constraint.conexclop.as_ref().map(Vec::len), Some(1));
    let index = lookup
        .index_relations_for_heap(relation.relation_oid)
        .into_iter()
        .find(|index| index.relation_oid == constraint.conindid)
        .unwrap();
    assert!(index.index_meta.indisexclusion);
    assert_eq!(index.index_meta.indkey, vec![0]);
    assert_eq!(index.index_meta.indexprs.as_deref(), Some("[\"1\"]"));
    drop(lookup);

    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_constraintdef(oid) from pg_constraint where conname = 'add_excl_expr_excl'",
        ),
        vec![vec![Value::Text("EXCLUDE USING gist ((1) WITH =)".into())]]
    );

    db.execute(1, "create table add_excl_expr_conflict(a int4)")
        .unwrap();
    db.execute(1, "insert into add_excl_expr_conflict values (1), (2)")
        .unwrap();
    match db.execute(
        1,
        "alter table add_excl_expr_conflict add constraint add_excl_expr_conflict_excl exclude ((1) with =)",
    ) {
        Err(ExecError::DetailedError {
            message, sqlstate, ..
        }) => {
            assert_eq!(sqlstate, "23P01");
            assert_eq!(
                message,
                "could not create exclusion constraint \"add_excl_expr_conflict_excl\""
            );
        }
        other => panic!("expected expression exclusion create violation, got {other:?}"),
    }
}

#[test]
fn polymorphic_range_sql_functions_infer_range_subtype() {
    let base = temp_dir("polymorphic_range_sql_functions");
    let db = Database::open(&base, 16).unwrap();

    db.execute(
        1,
        "create function anyarray_anyrange_func(a anyarray, r anyrange) \
         returns anyelement as 'select $1[1] + lower($2);' language sql",
    )
    .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select anyarray_anyrange_func(ARRAY[1,2], int4range(10,20))",
        ),
        vec![vec![Value::Int32(11)]],
    );
    match db.execute(
        1,
        "select anyarray_anyrange_func(ARRAY[1,2], numrange(10,20))",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError {
            message, sqlstate, ..
        })) => {
            assert_eq!(sqlstate, "42883");
            assert_eq!(
                message,
                "function anyarray_anyrange_func(integer[], numrange) does not exist"
            );
        }
        other => panic!("expected polymorphic mismatch error, got {other:?}"),
    }

    db.execute(
        1,
        "create function range_add_bounds(anyrange) \
         returns anyelement as 'select lower($1) + upper($1)' language sql",
    )
    .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select range_add_bounds(int4range(1, 17))"),
        vec![vec![Value::Int32(18)]],
    );
    assert_eq!(
        query_rows(&db, 1, "select range_add_bounds(numrange(1.0001, 123.123))"),
        vec![vec![Value::Numeric("124.1231".into())]],
    );
    assert!(
        db.execute(
            1,
            "create function bogus_range_result(anyelement) \
             returns anyrange as 'select int4range(1,10)' language sql",
        )
        .is_err()
    );
    assert!(
        db.execute(
            1,
            "create function bogus_range_result_int(int) \
             returns anyrange as 'select int4range(1,10)' language sql",
        )
        .is_err()
    );
}

#[test]
fn without_overlaps_primary_key_records_catalog_metadata_and_enforces_overlaps() {
    let base = temp_dir("without_overlaps_pk_enforcement");
    let db = Database::open(&base, 16).unwrap();

    db.execute(
        1,
        "create table temporal_items (\
             id int4, \
             valid_at int4range, \
             constraint temporal_items_pk primary key (id, valid_at without overlaps)\
         )",
    )
    .unwrap();

    let lookup = db.lazy_catalog_lookup(1, None, None);
    let relation = lookup.lookup_any_relation("temporal_items").unwrap();
    let constraint = lookup
        .constraint_rows_for_relation(relation.relation_oid)
        .into_iter()
        .find(|row| row.conname == "temporal_items_pk")
        .unwrap();
    assert!(constraint.conperiod);
    assert_eq!(constraint.conkey.as_deref(), Some(&[1, 2][..]));
    assert_eq!(constraint.conexclop.as_ref().map(Vec::len), Some(2));
    let index = lookup
        .index_relations_for_heap(relation.relation_oid)
        .into_iter()
        .find(|index| index.relation_oid == constraint.conindid)
        .unwrap();
    assert!(index.index_meta.indisexclusion);
    assert_eq!(
        psql_index_definition(&db, 1, "temporal_items", "temporal_items_pk"),
        "CREATE UNIQUE INDEX temporal_items_pk ON temporal_items USING gist (id, valid_at)"
    );
    drop(lookup);

    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_constraintdef(oid) from pg_constraint where conname = 'temporal_items_pk'",
        ),
        vec![vec![Value::Text(
            "PRIMARY KEY (id, valid_at WITHOUT OVERLAPS)".into()
        )]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef(conindid, 0, true) from pg_constraint where conname = 'temporal_items_pk'",
        ),
        vec![vec![Value::Text(
            "CREATE UNIQUE INDEX temporal_items_pk ON temporal_items USING gist (id, valid_at)"
                .into()
        )]]
    );

    db.execute(
        1,
        "insert into temporal_items values \
         (1, '[1,5)'::int4range), \
         (1, '[5,9)'::int4range), \
         (2, '[3,7)'::int4range)",
    )
    .unwrap();

    match db.execute(
        1,
        "insert into temporal_items values (1, '[4,6)'::int4range)",
    ) {
        Err(ExecError::DetailedError {
            message, sqlstate, ..
        }) => {
            assert_eq!(sqlstate, "23P01");
            assert_eq!(
                message,
                "conflicting key value violates exclusion constraint \"temporal_items_pk\""
            );
        }
        other => panic!("expected temporal exclusion violation, got {other:?}"),
    }

    assert_eq!(
        query_rows(&db, 1, "select count(*) from temporal_items"),
        vec![vec![Value::Int64(3)]]
    );
}

