#[test]
fn identity_regression_insert_privilege_bypasses_sequence_privilege() {
    let db = Database::open_ephemeral(64).expect("open ephemeral database");
    let mut owner = Session::new(1);
    let mut app = Session::new(2);

    owner.execute(&db, "create role identity_app").unwrap();
    owner
        .execute(
            &db,
            "create table priv_identity (a int generated by default as identity, b text)",
        )
        .unwrap();
    owner
        .execute(&db, "grant insert on priv_identity to identity_app")
        .unwrap();
    app.execute(&db, "set session authorization identity_app")
        .unwrap();

    app.execute(&db, "insert into priv_identity (b) values ('ok')")
        .unwrap();
    assert_sqlstate(
        app.execute(&db, "select nextval('priv_identity_a_seq')")
            .unwrap_err(),
        "42501",
        "permission denied for sequence priv_identity_a_seq",
    );
    assert_eq!(
        session_query_rows(&mut owner, &db, "select a, b from priv_identity"),
        vec![vec![Value::Int32(1), Value::Text("ok".into())]]
    );
}

#[test]
fn identity_regression_merge_and_view_overriding_use_identity_defaults() {
    let db = Database::open_ephemeral(64).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table merge_identity (
                id int generated always as identity,
                k int unique
            )",
        )
        .unwrap();
    session
        .execute(&db, "insert into merge_identity (k) values (1)")
        .unwrap();
    session
        .execute(
            &db,
            "merge into merge_identity t
             using (values (2)) as s(k) on t.k = s.k
             when not matched then
               insert (id, k) overriding user value values (99, s.k)",
        )
        .unwrap();

    assert_sqlstate(
        session
            .execute(
                &db,
                "merge into merge_identity t
                 using (values (3)) as s(k) on t.k = s.k
                 when not matched then insert (id, k) values (77, s.k)",
            )
            .unwrap_err(),
        "428C9",
        "cannot insert a non-DEFAULT value into column \"id\"",
    );
    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select id, k from merge_identity order by k",
        ),
        vec![
            vec![Value::Int32(1), Value::Int32(1)],
            vec![Value::Int32(2), Value::Int32(2)],
        ]
    );

    session
        .execute(
            &db,
            "create table view_identity (
                id int generated always as identity,
                note text
            )",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create view view_identity_v as select id, note from view_identity",
        )
        .unwrap();
    assert_sqlstate(
        session
            .execute(&db, "insert into view_identity_v values (77, 'blocked')")
            .unwrap_err(),
        "428C9",
        "cannot insert a non-DEFAULT value into column \"id\"",
    );
    session
        .execute(
            &db,
            "insert into view_identity_v (id, note)
             overriding user value values (77, 'view')",
        )
        .unwrap();
    assert_eq!(
        session_query_rows(&mut session, &db, "select id, note from view_identity"),
        vec![vec![Value::Int32(1), Value::Text("view".into())]]
    );
}

#[test]
fn identity_regression_partition_attach_detach_tracks_parent_identity() {
    let db = Database::open_ephemeral(64).expect("open ephemeral database");

    db.execute(
        1,
        "create table part_identity (
            a int generated by default as identity,
            p int not null
        ) partition by range (p)",
    )
    .unwrap();
    db.execute(
        1,
        "create table part_identity_child (a int not null, p int not null)",
    )
    .unwrap();
    db.execute(
        1,
        "alter table part_identity
         attach partition part_identity_child for values from (0) to (10)",
    )
    .unwrap();

    db.execute(1, "insert into part_identity (p) values (1)")
        .unwrap();
    db.execute(1, "insert into part_identity_child (p) values (2)")
        .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select a, p from part_identity_child order by p"),
        vec![
            vec![Value::Int32(1), Value::Int32(1)],
            vec![Value::Int32(2), Value::Int32(2)],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select c.relname, a.attidentity
             from pg_class c
             join pg_attribute a on a.attrelid = c.oid
             where c.relname in ('part_identity', 'part_identity_child')
               and a.attname = 'a'
             order by c.relname",
        ),
        vec![
            vec![Value::Text("part_identity".into()), Value::Text("d".into()),],
            vec![
                Value::Text("part_identity_child".into()),
                Value::Text("d".into()),
            ],
        ]
    );

    db.execute(
        1,
        "alter table part_identity detach partition part_identity_child",
    )
    .unwrap();
    match db.execute(1, "insert into part_identity_child (p) values (3)") {
        Err(ExecError::NotNullViolation { column, .. }) => assert_eq!(column, "a"),
        other => panic!("expected detached identity default to be cleared, got {other:?}"),
    }
    assert_eq!(
        query_rows(
            &db,
            1,
            "select attidentity, attnotnull
             from pg_attribute
             where attrelid = 'part_identity_child'::regclass and attname = 'a'",
        ),
        vec![vec![Value::Text("".into()), Value::Bool(true)]]
    );
}

