#[test]
fn alter_table_check_validation_uses_validation_errors_and_checks_children() {
    let base = temp_dir("alter_check_validation_wording");
    let db = Database::open(&base, 64).unwrap();

    db.execute(1, "create table check_parent (a int4, b int4)")
        .unwrap();
    db.execute(1, "insert into check_parent values (1, 10), (1, 20)")
        .unwrap();

    match db.execute(
        1,
        "alter table check_parent add constraint b_greater_than_ten check (b > 10)",
    ) {
        Err(ExecError::DetailedError {
            message,
            detail,
            sqlstate,
            ..
        }) if message
            == "check constraint \"b_greater_than_ten\" of relation \"check_parent\" is violated by some row"
            && detail.is_none()
            && sqlstate == "23514" => {}
        other => panic!("expected DDL check validation failure, got {other:?}"),
    }

    db.execute(
        1,
        "alter table check_parent add constraint b_greater_than_ten check (b > 10) not valid",
    )
    .unwrap();
    match db.execute(
        1,
        "alter table check_parent validate constraint b_greater_than_ten",
    ) {
        Err(ExecError::DetailedError { message, .. })
            if message
                == "check constraint \"b_greater_than_ten\" of relation \"check_parent\" is violated by some row" =>
            {}
        other => panic!("expected DDL validate check failure, got {other:?}"),
    }

    db.execute(1, "delete from check_parent where not b > 10")
        .unwrap();
    db.execute(
        1,
        "alter table check_parent validate constraint b_greater_than_ten",
    )
    .unwrap();
    db.execute(1, "create table check_child () inherits (check_parent)")
        .unwrap();
    db.execute(1, "insert into check_child values (6, 30), (7, 16)")
        .unwrap();
    db.execute(
        1,
        "alter table check_parent add constraint b_le_20 check (b <= 20) not valid",
    )
    .unwrap();

    match db.execute(1, "alter table check_parent validate constraint b_le_20") {
        Err(ExecError::DetailedError { message, .. })
            if message
                == "check constraint \"b_le_20\" of relation \"check_child\" is violated by some row" =>
            {}
        other => panic!("expected child DDL validate check failure, got {other:?}"),
    }
}

#[test]
fn inherited_check_rejects_not_enforced_or_not_valid_child_conflicts() {
    let base = temp_dir("check_inherit_conflicts");
    let db = Database::open(&base, 16).unwrap();

    db.execute(
        1,
        "create table chk_parent (a int4 constraint chk_a check (a > 0) enforced)",
    )
    .unwrap();
    db.execute(
        1,
        "create table chk_child (a int4 constraint chk_a check (a > 0) not enforced)",
    )
    .unwrap();
    match db.execute(1, "alter table chk_child inherit chk_parent") {
        Err(ExecError::DetailedError {
            message, sqlstate, ..
        }) => {
            assert_eq!(
                message,
                "constraint \"chk_a\" conflicts with NOT ENFORCED constraint on child table \"chk_child\""
            );
            assert_eq!(sqlstate, "42P17");
        }
        other => panic!("expected NOT ENFORCED child CHECK conflict, got {other:?}"),
    }

    db.execute(1, "create table chk_valid_parent (a int4)")
        .unwrap();
    db.execute(
        1,
        "create table chk_invalid_child () inherits (chk_valid_parent)",
    )
    .unwrap();
    db.execute(
        1,
        "alter table chk_invalid_child add constraint chk_valid check (a > 0) not valid",
    )
    .unwrap();
    match db.execute(
        1,
        "alter table chk_valid_parent add constraint chk_valid check (a > 0)",
    ) {
        Err(ExecError::DetailedError {
            message, sqlstate, ..
        }) => {
            assert_eq!(
                message,
                "constraint \"chk_valid\" conflicts with NOT VALID constraint on relation \"chk_invalid_child\""
            );
            assert_eq!(sqlstate, "42P17");
        }
        other => panic!("expected NOT VALID child CHECK conflict, got {other:?}"),
    }
}

#[test]
fn alter_table_check_validation_has_executor_catalog_for_functions() {
    let base = temp_dir("alter_check_validation_function_catalog");
    let db = Database::open(&base, 64).unwrap();

    db.execute(1, "create table func_parent (a int4, b int4)")
        .unwrap();
    db.execute(1, "create table func_child1 () inherits (func_parent)")
        .unwrap();
    db.execute(1, "create table func_child2 () inherits (func_parent)")
        .unwrap();
    db.execute(1, "insert into func_parent values (1, 20)")
        .unwrap();
    db.execute(1, "insert into func_child1 values (7, 16)")
        .unwrap();
    db.execute(1, "insert into func_child2 values (8, 18)")
        .unwrap();
    db.execute(
        1,
        "create function boo(int) returns int immutable strict language plpgsql as $$ begin raise notice 'boo: %', $1; return $1; end $$",
    )
    .unwrap();

    clear_notices();
    db.execute(
        1,
        "alter table func_child2 add constraint identity check (b = boo(b))",
    )
    .unwrap();
    assert_eq!(take_notice_messages(), vec!["boo: 18".to_string()]);

    clear_backend_notices();
    db.execute(
        1,
        "alter table func_parent add constraint identity check (b = boo(b)) not valid",
    )
    .unwrap();
    assert_eq!(
        take_backend_notice_messages(),
        vec!["merging constraint \"identity\" with inherited definition".to_string()]
    );

    clear_notices();
    db.execute(1, "alter table func_parent validate constraint identity")
        .unwrap();
    assert_eq!(
        take_notice_messages(),
        vec!["boo: 20".to_string(), "boo: 16".to_string()]
    );
}

#[test]
fn update_and_copy_from_enforce_check_and_not_null_constraints() {
    let base = temp_dir("update_and_copy_constraint_checks");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    db.execute(
        1,
        "create table items (
            id int4 constraint items_id_positive check (id > 0),
            note text constraint items_note_required not null
        )",
    )
    .unwrap();
    db.execute(1, "insert into items values (1, 'ok')").unwrap();

    match db.execute(1, "update items set id = 0 where id = 1") {
        Err(ExecError::CheckViolation {
            relation,
            constraint,
            ..
        }) if relation == "items" && constraint == "items_id_positive" => {}
        other => panic!("expected update check violation, got {other:?}"),
    }

    match db.execute(1, "update items set note = null where id = 1") {
        Err(ExecError::NotNullViolation {
            relation,
            column,
            constraint,
            ..
        }) if relation == "items" && column == "note" && constraint == "items_note_required" => {}
        other => panic!("expected update not-null violation, got {other:?}"),
    }

    let err = session
        .copy_from_rows(&db, "items", &[vec!["0".into(), "copy".into()]])
        .unwrap_err();
    match root_error(&err) {
        ExecError::CheckViolation {
            relation,
            constraint,
            ..
        } if relation == "items" && constraint == "items_id_positive" => {}
        other => panic!("expected copy check violation, got {other:?}"),
    }

    let err = session
        .copy_from_rows(&db, "items", &[vec!["2".into(), "\\N".into()]])
        .unwrap_err();
    match root_error(&err) {
        ExecError::NotNullViolation {
            relation,
            column,
            constraint,
            ..
        } if relation == "items" && column == "note" && constraint == "items_note_required" => {}
        other => panic!("expected copy not-null violation, got {other:?}"),
    }

    assert_eq!(
        query_rows(&db, 1, "select id, note from items order by id"),
        vec![vec![Value::Int32(1), Value::Text("ok".into())]]
    );
}

#[test]
fn prepared_insert_enforces_check_and_not_null_constraints() {
    let base = temp_dir("prepared_insert_constraints");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    db.execute(
        1,
        "create table items (
            id int4 constraint items_id_positive check (id > 0),
            note text constraint items_note_required not null
        )",
    )
    .unwrap();

    let prepared = session.prepare_insert(&db, "items", None, 2).unwrap();
    session.execute(&db, "begin").unwrap();

    match session.execute_prepared_insert(
        &db,
        &prepared,
        &[Value::Int32(0), Value::Text("bad".into())],
    ) {
        Err(ExecError::CheckViolation {
            relation,
            constraint,
            ..
        }) if relation == "items" && constraint == "items_id_positive" => {}
        other => panic!("expected prepared-insert check violation, got {other:?}"),
    }
    assert!(session.transaction_failed());
    session.execute(&db, "rollback").unwrap();

    session.execute(&db, "begin").unwrap();
    match session.execute_prepared_insert(&db, &prepared, &[Value::Int32(2), Value::Null]) {
        Err(ExecError::NotNullViolation {
            relation,
            column,
            constraint,
            ..
        }) if relation == "items" && column == "note" && constraint == "items_note_required" => {}
        other => panic!("expected prepared-insert not-null violation, got {other:?}"),
    }
    assert!(session.transaction_failed());
    session.execute(&db, "rollback").unwrap();

    session.execute(&db, "begin").unwrap();
    session
        .execute_prepared_insert(&db, &prepared, &[Value::Int32(3), Value::Text("ok".into())])
        .unwrap();
    session.execute(&db, "commit").unwrap();

    assert_eq!(
        query_rows(&db, 1, "select id, note from items"),
        vec![vec![Value::Int32(3), Value::Text("ok".into())]]
    );
}

#[test]
fn prepared_insert_and_copy_from_enforce_foreign_keys() {
    let base = temp_dir("prepared_insert_copy_foreign_keys");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    db.execute(1, "create table parents (id int4 primary key)")
        .unwrap();
    db.execute(
        1,
        "create table children (id int4 primary key, parent_id int4 references parents)",
    )
    .unwrap();
    db.execute(1, "insert into parents values (1)").unwrap();

    let err = session
        .copy_from_rows(&db, "children", &[vec!["1".into(), "2".into()]])
        .unwrap_err();
    match root_error(&err) {
        ExecError::ForeignKeyViolation { constraint, .. } => {
            assert_eq!(constraint, "children_parent_id_fkey");
        }
        other => panic!("expected COPY foreign-key violation, got {other:?}"),
    }

    let prepared = session.prepare_insert(&db, "children", None, 2).unwrap();
    session.execute(&db, "begin").unwrap();
    match session.execute_prepared_insert(&db, &prepared, &[Value::Int32(1), Value::Int32(2)]) {
        Err(ExecError::ForeignKeyViolation { constraint, .. }) => {
            assert_eq!(constraint, "children_parent_id_fkey");
        }
        other => panic!("expected prepared foreign-key violation, got {other:?}"),
    }
    assert!(session.transaction_failed());
    session.execute(&db, "rollback").unwrap();

    session.execute(&db, "begin").unwrap();
    session
        .execute_prepared_insert(&db, &prepared, &[Value::Int32(1), Value::Int32(1)])
        .unwrap();
    session.execute(&db, "commit").unwrap();

    assert_eq!(
        query_rows(&db, 1, "select id, parent_id from children"),
        vec![vec![Value::Int32(1), Value::Int32(1)]]
    );
}

#[test]
fn alter_table_add_constraints_support_not_valid_and_validate() {
    let base = temp_dir("alter_table_add_constraints_validate");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table items (id int4, note text)")
        .unwrap();
    db.execute(1, "insert into items values (0, null), (2, 'ok')")
        .unwrap();

    db.execute(
        1,
        "alter table items add constraint items_id_positive check (id > 0) not valid",
    )
    .unwrap();
    db.execute(
        1,
        "alter table items add constraint items_note_required not null note not valid",
    )
    .unwrap();

    match db.execute(1, "insert into items values (0, 'later')") {
        Err(ExecError::CheckViolation {
            relation,
            constraint,
            ..
        }) if relation == "items" && constraint == "items_id_positive" => {}
        other => panic!("expected ALTER TABLE CHECK violation, got {other:?}"),
    }

    match db.execute(1, "insert into items values (3, null)") {
        Err(ExecError::NotNullViolation {
            relation,
            column,
            constraint,
            ..
        }) if relation == "items" && column == "note" && constraint == "items_note_required" => {}
        other => panic!("expected ALTER TABLE NOT NULL violation, got {other:?}"),
    }

    let rows = query_rows(
        &db,
        1,
        "select conname, contype, convalidated, array_length(conkey, 1), conbin \
         from pg_constraint \
         where conrelid = (select oid from pg_class where relname = 'items') \
         order by conname",
    );
    assert_eq!(rows.len(), 2);
    assert_eq!(rows[0][0], Value::Text("items_id_positive".into()));
    assert_eq!(rows[0][1], Value::Text("c".into()));
    assert_eq!(rows[0][2], Value::Bool(false));
    assert_eq!(rows[0][3], Value::Null);
    assert_eq!(rows[0][4], Value::Text("id > 0".into()));
    assert_eq!(rows[1][0], Value::Text("items_note_required".into()));
    assert_eq!(rows[1][1], Value::Text("n".into()));
    assert_eq!(rows[1][2], Value::Bool(false));
    assert_eq!(int_value(&rows[1][3]), 1);
    assert_eq!(rows[1][4], Value::Null);

    match db.execute(1, "alter table items validate constraint items_id_positive") {
        Err(ExecError::DetailedError {
            message,
            detail,
            sqlstate,
            ..
        }) if message
            == "check constraint \"items_id_positive\" of relation \"items\" is violated by some row"
            && detail.is_none()
            && sqlstate == "23514" => {}
        other => panic!("expected CHECK validate failure, got {other:?}"),
    }

    match db.execute(
        1,
        "alter table items validate constraint items_note_required",
    ) {
        Err(ExecError::DetailedError {
            message,
            detail,
            sqlstate,
            ..
        }) if message == "column \"note\" of relation \"items\" contains null values"
            && detail.is_none()
            && sqlstate == "23502" => {}
        other => panic!("expected NOT NULL validate failure, got {other:?}"),
    }

    db.execute(
        1,
        "update items set id = 1, note = 'filled' where id = 0 and note is null",
    )
    .unwrap();
    db.execute(1, "alter table items validate constraint items_id_positive")
        .unwrap();
    db.execute(
        1,
        "alter table items validate constraint items_note_required",
    )
    .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select conname, convalidated \
             from pg_constraint \
             where conrelid = (select oid from pg_class where relname = 'items') \
             order by conname",
        ),
        vec![
            vec![Value::Text("items_id_positive".into()), Value::Bool(true)],
            vec![Value::Text("items_note_required".into()), Value::Bool(true)],
        ]
    );
}

#[test]
fn not_null_not_valid_blocks_pk_and_identity_until_validated() {
    let base = temp_dir("not_null_not_valid_pk_identity");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table nn_pk_identity (a int4, b int4)")
        .unwrap();
    db.execute(1, "insert into nn_pk_identity values (null, 1), (2, 2)")
        .unwrap();
    db.execute(
        1,
        "alter table nn_pk_identity add constraint nn_a not null a not valid",
    )
    .unwrap();

    match db.execute(1, "alter table nn_pk_identity add primary key (a)") {
        Err(ExecError::DetailedError {
            message,
            detail,
            hint,
            sqlstate,
        }) => {
            assert_eq!(message, "cannot create primary key on column \"a\"");
            assert_eq!(
                detail.as_deref(),
                Some(
                    "The constraint \"nn_a\" on column \"a\" of table \"nn_pk_identity\", marked NOT VALID, is incompatible with a primary key."
                )
            );
            assert_eq!(
                hint.as_deref(),
                Some("You might need to validate it using ALTER TABLE ... VALIDATE CONSTRAINT.")
            );
            assert_eq!(sqlstate, "55000");
        }
        other => panic!("expected invalid NOT NULL to block primary key, got {other:?}"),
    }

    match db.execute(
        1,
        "alter table nn_pk_identity alter column a add generated always as identity",
    ) {
        Err(ExecError::DetailedError {
            message,
            hint,
            sqlstate,
            ..
        }) => {
            assert_eq!(
                message,
                "incompatible NOT VALID constraint \"nn_a\" on relation \"nn_pk_identity\""
            );
            assert_eq!(
                hint.as_deref(),
                Some("You might need to validate it using ALTER TABLE ... VALIDATE CONSTRAINT.")
            );
            assert_eq!(sqlstate, "55000");
        }
        other => panic!("expected invalid NOT NULL to block identity, got {other:?}"),
    }

    match db.execute(1, "alter table nn_pk_identity alter column a set not null") {
        Err(ExecError::DetailedError {
            message,
            detail,
            sqlstate,
            ..
        }) if message == "column \"a\" of relation \"nn_pk_identity\" contains null values"
            && detail.is_none()
            && sqlstate == "23502" => {}
        other => panic!("expected SET NOT NULL validation failure, got {other:?}"),
    }

    db.execute(1, "update nn_pk_identity set a = 1 where a is null")
        .unwrap();
    db.execute(1, "alter table nn_pk_identity alter column a set not null")
        .unwrap();
    db.execute(1, "alter table nn_pk_identity add primary key (a)")
        .unwrap();
}

