#[test]
fn foreign_keys_block_parent_ddl_and_allow_child_drop() {
    let base = temp_dir("foreign_key_ddl_blockers");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table parents (id int4 primary key)")
        .unwrap();
    db.execute(
        1,
        "create table children (id int4 primary key, parent_id int4 references parents)",
    )
    .unwrap();
    db.execute(1, "insert into parents values (1)").unwrap();
    db.execute(1, "insert into children values (1, 1)").unwrap();

    for sql in [
        "drop table parents",
        "truncate parents",
        "alter table parents drop column id",
        "alter table parents drop constraint parents_pkey",
    ] {
        match db.execute(1, sql) {
            Err(ExecError::DetailedError {
                message,
                detail: Some(detail),
                ..
            }) if detail.contains("foreign key constraint")
                || detail.contains("depends on table")
                || detail.contains("depends on")
                || (message
                    == "cannot truncate a table referenced in a foreign key constraint"
                    && detail.contains("references")) => {}
            Err(ExecError::Parse(ParseError::UnexpectedToken { actual, .. }))
                if actual.contains("foreign key constraint")
                    || actual.contains("referenced by foreign key")
                    || actual.contains("used by foreign key") => {}
            other => panic!("expected foreign-key DDL blocker for `{sql}`, got {other:?}"),
        }
    }

    db.execute(1, "alter table parents alter column id type int8")
        .unwrap();
    db.execute(1, "alter table children alter column parent_id type int8")
        .unwrap();

    db.execute(
        1,
        "create table child_column_drop (
            id int4 primary key,
            parent_id int8 constraint child_column_drop_fk references parents
        )",
    )
    .unwrap();
    clear_backend_notices();
    db.execute(1, "alter table child_column_drop drop column parent_id")
        .unwrap();
    assert_eq!(take_backend_notices().len(), 0);
    assert_eq!(
        query_rows(
            &db,
            1,
            "select count(*) from pg_constraint where conname = 'child_column_drop_fk'",
        ),
        vec![vec![Value::Int64(0)]]
    );

    db.execute(1, "drop table child_column_drop").unwrap();
    db.execute(1, "drop table children").unwrap();
    db.execute(1, "drop table parents").unwrap();
}

fn assert_period_fk_action_error(result: Result<StatementResult, ExecError>, expected: &str) {
    match result {
        Err(ExecError::DetailedError { message, .. })
        | Err(ExecError::Parse(ParseError::DetailedError { message, .. }))
            if message == expected => {}
        other => panic!("expected PERIOD FK action error `{expected}`, got {other:?}"),
    }
}

#[test]
fn without_overlaps_remaining_period_foreign_keys_reject_unsupported_actions_before_catalog_writes()
{
    let base = temp_dir("period_fk_action_validation");
    let db = Database::open(&base, 16).unwrap();

    db.execute(
        1,
        "create table period_parent (
            id int4,
            valid_at int4range,
            primary key (id, valid_at without overlaps)
        )",
    )
    .unwrap();

    assert_period_fk_action_error(
        db.execute(
            1,
            "create table period_child_bad (
                id int4 primary key,
                parent_id int4,
                valid_at int4range,
                foreign key (parent_id, period valid_at)
                    references period_parent (id, period valid_at)
                    on update cascade
            )",
        ),
        "unsupported ON UPDATE action for foreign key constraint using PERIOD",
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select count(*) from pg_class where relname = 'period_child_bad'",
        ),
        vec![vec![Value::Int64(0)]]
    );

    db.execute(
        1,
        "create table period_child_alter (
            id int4 primary key,
            parent_id int4,
            valid_at int4range
        )",
    )
    .unwrap();
    assert_period_fk_action_error(
        db.execute(
            1,
            "alter table period_child_alter
             add constraint period_child_alter_fk
             foreign key (parent_id, period valid_at)
             references period_parent (id, period valid_at)
             on delete set null",
        ),
        "unsupported ON DELETE action for foreign key constraint using PERIOD",
    );
    assert_period_fk_action_error(
        db.execute(
            1,
            "alter table period_child_alter
             alter column parent_id set default 0,
             add constraint period_child_alter_fk
             foreign key (parent_id, period valid_at)
             references period_parent (id, period valid_at)
             on delete set default on update set default",
        ),
        "unsupported ON UPDATE action for foreign key constraint using PERIOD",
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select count(*) from pg_constraint where conname = 'period_child_alter_fk'",
        ),
        vec![vec![Value::Int64(0)]]
    );
}

