#[test]
fn create_index_expression_stats_and_collation_deparse_match_postgres() {
    let base = temp_dir("create_index_expr_collation_deparse");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table concur_exprs_tab (c1 int, c2 boolean)")
        .unwrap();
    db.execute(
        1,
        "insert into concur_exprs_tab values \
         (1369652450, false), (414515746, true), (897778963, false)",
    )
    .unwrap();
    db.execute(
        1,
        "create unique index concur_exprs_index_expr \
         on concur_exprs_tab ((c1::text collate \"C\"))",
    )
    .unwrap();
    db.execute(
        1,
        "create unique index concur_exprs_index_pred on concur_exprs_tab (c1) \
         where (c1::text > 500000000::text collate \"C\")",
    )
    .unwrap();
    db.execute(
        1,
        "create unique index concur_exprs_index_pred_2 \
         on concur_exprs_tab ((1 / c1)) \
         where ('-H') >= (c2::text) collate \"C\"",
    )
    .unwrap();
    db.execute(
        1,
        "alter index concur_exprs_index_expr alter column 1 set statistics 100",
    )
    .unwrap();
    db.execute(1, "analyze concur_exprs_tab").unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select starelid::regclass::text, count(*) \
             from pg_statistic \
             where starelid in (\
               'concur_exprs_index_expr'::regclass, \
               'concur_exprs_index_pred'::regclass, \
               'concur_exprs_index_pred_2'::regclass) \
             group by starelid order by starelid::regclass::text",
        ),
        vec![
            vec![
                Value::Text("concur_exprs_index_expr".into()),
                Value::Int64(1),
            ],
            vec![
                Value::Text("concur_exprs_index_pred_2".into()),
                Value::Int64(1),
            ],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef('concur_exprs_index_expr'::regclass)",
        ),
        vec![vec![Value::Text(
            "CREATE UNIQUE INDEX concur_exprs_index_expr ON public.concur_exprs_tab USING btree (((c1)::text) COLLATE \"C\")".into()
        )]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef('concur_exprs_index_pred'::regclass)",
        ),
        vec![vec![Value::Text(
            "CREATE UNIQUE INDEX concur_exprs_index_pred ON public.concur_exprs_tab USING btree (c1) WHERE ((c1)::text > ((500000000)::text COLLATE \"C\"))".into()
        )]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef('concur_exprs_index_pred_2'::regclass)",
        ),
        vec![vec![Value::Text(
            "CREATE UNIQUE INDEX concur_exprs_index_pred_2 ON public.concur_exprs_tab USING btree (((1 / c1))) WHERE ('-H'::text >= ((c2)::text COLLATE \"C\"))".into()
        )]]
    );

    db.execute(1, "alter table concur_exprs_tab alter c2 type text")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select pg_get_indexdef('concur_exprs_index_pred_2'::regclass)",
        ),
        vec![vec![Value::Text(
            "CREATE UNIQUE INDEX concur_exprs_index_pred_2 ON public.concur_exprs_tab USING btree (((1 / c1))) WHERE ('-H'::text >= (c2 COLLATE \"C\"))".into()
        )]]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select attrelid::regclass::text, attnum, attstattarget \
             from pg_attribute \
             where attrelid in (\
               'concur_exprs_index_expr'::regclass, \
               'concur_exprs_index_pred'::regclass, \
               'concur_exprs_index_pred_2'::regclass) \
             order by attrelid::regclass::text, attnum",
        ),
        vec![
            vec![
                Value::Text("concur_exprs_index_expr".into()),
                Value::Int16(1),
                Value::Int16(100),
            ],
            vec![
                Value::Text("concur_exprs_index_pred".into()),
                Value::Int16(1),
                Value::Null,
            ],
            vec![
                Value::Text("concur_exprs_index_pred_2".into()),
                Value::Int16(1),
                Value::Null,
            ],
        ]
    );
}

#[test]
fn partial_unique_index_build_and_insert_only_enforce_qualifying_rows() {
    let base = temp_dir("partial_unique_index_build");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create table items (id int4, flag text, note text)")
        .unwrap();
    db.execute(
        1,
        "insert into items values \
         (1, 'skip', 'outside1'), \
         (1, 'skip', 'outside2'), \
         (2, 'keep', 'inside')",
    )
    .unwrap();
    db.execute(
        1,
        "create unique index items_keep_key on items (id) where flag = 'keep'",
    )
    .unwrap();

    db.execute(1, "insert into items values (1, 'skip', 'outside3')")
        .unwrap();

    match db.execute(1, "insert into items values (2, 'keep', 'dup')") {
        Err(ExecError::UniqueViolation { constraint, detail }) => {
            assert_eq!(constraint, "items_keep_key");
            assert_eq!(detail.as_deref(), Some("Key (id)=(2) already exists."));
        }
        other => panic!("expected unique violation, got {:?}", other),
    }

    assert_eq!(
        query_rows(
            &db,
            1,
            "select id, flag, note from items order by id, flag, note"
        ),
        vec![
            vec![
                Value::Int32(1),
                Value::Text("skip".into()),
                Value::Text("outside1".into()),
            ],
            vec![
                Value::Int32(1),
                Value::Text("skip".into()),
                Value::Text("outside2".into()),
            ],
            vec![
                Value::Int32(1),
                Value::Text("skip".into()),
                Value::Text("outside3".into()),
            ],
            vec![
                Value::Int32(2),
                Value::Text("keep".into()),
                Value::Text("inside".into()),
            ],
        ]
    );
}

#[test]
fn unique_array_column_supports_duplicates_and_index_quals() {
    let base = temp_dir("unique_array_column_supports_duplicates_and_index_quals");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create temp table arr_tbl (f1 int[] unique)")
        .unwrap();
    db.execute(1, "insert into arr_tbl values ('{1,2,3}')")
        .unwrap();
    db.execute(1, "insert into arr_tbl values ('{1,2}')")
        .unwrap();
    db.execute(1, "insert into arr_tbl values ('{2,3,4}')")
        .unwrap();
    db.execute(1, "insert into arr_tbl values ('{1,5,3}')")
        .unwrap();
    db.execute(1, "insert into arr_tbl values ('{1,2,10}')")
        .unwrap();

    match db.execute(1, "insert into arr_tbl values ('{1,2,3}')") {
        Err(ExecError::UniqueViolation { constraint, detail }) => {
            assert_eq!(constraint, "arr_tbl_f1_key");
            assert_eq!(
                detail.as_deref(),
                Some("Key (f1)=({1,2,3}) already exists.")
            );
        }
        other => panic!("expected unique violation, got {:?}", other),
    }

    db.execute(1, "set enable_seqscan to off").unwrap();
    db.execute(1, "set enable_bitmapscan to off").unwrap();
    assert_explain_uses_index(
        &db,
        1,
        "select * from arr_tbl where f1 > '{1,2,3}' and f1 <= '{1,5,3}'",
        "arr_tbl_f1_key",
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select * from arr_tbl where f1 > '{1,2,3}' and f1 <= '{1,5,3}'"
        ),
        vec![
            vec![Value::PgArray(
                crate::include::nodes::datum::ArrayValue::from_1d(vec![
                    Value::Int32(1),
                    Value::Int32(2),
                    Value::Int32(10),
                ])
                .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
            )],
            vec![Value::PgArray(
                crate::include::nodes::datum::ArrayValue::from_1d(vec![
                    Value::Int32(1),
                    Value::Int32(5),
                    Value::Int32(3),
                ])
                .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
            )],
        ]
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select * from arr_tbl where f1 >= '{1,2,3}' and f1 < '{1,5,3}'"
        ),
        vec![
            vec![Value::PgArray(
                crate::include::nodes::datum::ArrayValue::from_1d(vec![
                    Value::Int32(1),
                    Value::Int32(2),
                    Value::Int32(3),
                ])
                .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
            )],
            vec![Value::PgArray(
                crate::include::nodes::datum::ArrayValue::from_1d(vec![
                    Value::Int32(1),
                    Value::Int32(2),
                    Value::Int32(10),
                ])
                .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
            )],
        ]
    );
}

