#[test]
fn btree_prunes_aborted_leaf_entries_when_page_is_full() {
    let base = temp_dir("btree_prunes_aborted_leaf_entries");
    let db = Database::open(&base, 64).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create table items (id int4 not null, note text)")
        .unwrap();
    session
        .execute(&db, "create index items_id_idx on items (id)")
        .unwrap();

    session.execute(&db, "begin").unwrap();
    session
        .execute(&db, &insert_items_sql(0..1800, "aborted"))
        .unwrap();
    session.execute(&db, "rollback").unwrap();

    let index_rel = relation_locator_for(&db, 1, "items_id_idx");
    let aborted_blocks = relation_fork_nblocks(
        &db,
        index_rel,
        crate::backend::storage::smgr::ForkNumber::Main,
    );
    let aborted_tuples = btree_leaf_tuple_count(&db, 1, index_rel);
    assert_eq!(
        query_rows(&db, 1, "select count(*) from items"),
        vec![vec![Value::Int64(0)]]
    );
    assert!(
        aborted_tuples >= 1800,
        "expected rollback to leave aborted index entries, got {aborted_tuples}"
    );

    session
        .execute(&db, &insert_items_sql(0..1800, "live"))
        .unwrap();

    let live_blocks = relation_fork_nblocks(
        &db,
        index_rel,
        crate::backend::storage::smgr::ForkNumber::Main,
    );
    let live_tuples = btree_leaf_tuple_count(&db, 1, index_rel);
    assert!(
        live_blocks <= aborted_blocks + 2,
        "expected page-pressure pruning to avoid index growth, blocks {aborted_blocks} -> {live_blocks}"
    );
    assert!(
        live_tuples < aborted_tuples + 1800,
        "expected pruning to remove at least some aborted entries, tuples {aborted_tuples} -> {live_tuples}"
    );
    assert_explain_uses_index(
        &db,
        1,
        "select note from items where id = 42",
        "items_id_idx",
    );
    assert_eq!(
        query_rows(&db, 1, "select note from items where id = 42"),
        vec![vec![Value::Text("live42".into())]]
    );
}

#[test]
fn concurrent_indexed_inserts_and_lookups_remain_correct() {
    let base = temp_dir("concurrent_indexed_inserts_and_lookups");
    let db = Database::open(&base, 64).unwrap();

    db.execute(1, "create table items (id int4 not null, note text)")
        .unwrap();
    db.execute(1, "create index items_id_idx on items (id)")
        .unwrap();

    let writers: Vec<_> = (0..4)
        .map(|worker| {
            let db = db.clone();
            std::thread::spawn(move || {
                for i in 0..60 {
                    let id = worker * 1000 + i;
                    db.execute(
                        (worker + 10) as ClientId,
                        &format!("insert into items values ({id}, 'w{worker}-{i}')"),
                    )
                    .unwrap();
                    let rows =
                        query_rows(&db, 1, &format!("select note from items where id = {id}"));
                    assert_eq!(rows.len(), 1, "expected one row for id {id}, got {rows:?}");
                }
            })
        })
        .collect();

    let readers: Vec<_> = (0..2)
        .map(|reader| {
            let db = db.clone();
            std::thread::spawn(move || {
                for i in 0..60 {
                    let id = (i % 60) as i32;
                    db.execute(
                        (reader + 100) as ClientId,
                        &format!("select note from items where id = {id}"),
                    )
                    .unwrap();
                }
            })
        })
        .collect();

    join_all_with_timeout(writers, HEAVY_CONTENTION_TEST_TIMEOUT);
    join_all_with_timeout(readers, HEAVY_CONTENTION_TEST_TIMEOUT);

    assert_eq!(
        query_rows(&db, 1, "select count(*) from items"),
        vec![vec![Value::Int64(240)]]
    );
    assert_explain_uses_index(
        &db,
        1,
        "select note from items where id = 1005",
        "items_id_idx",
    );
    assert_eq!(
        query_rows(&db, 1, "select note from items where id = 1005"),
        vec![vec![Value::Text("w1-5".into())]]
    );
}

#[test]
fn concurrent_indexed_inserts_and_range_scans_survive_splits() {
    let base = temp_dir("concurrent_indexed_inserts_and_range_scans_survive_splits");
    let db = Database::open(&base, 128).unwrap();

    db.execute(1, "create table items (id int4 not null, note text)")
        .unwrap();
    db.execute(1, "create index items_id_idx on items (id)")
        .unwrap();

    let writers: Vec<_> = (0..4)
        .map(|worker| {
            let db = db.clone();
            thread::spawn(move || {
                for i in 0..120 {
                    let id = worker * 10_000 + i;
                    db.execute(
                        (worker + 20) as ClientId,
                        &format!("insert into items values ({id}, 'w{worker}-{i}')"),
                    )
                    .unwrap();
                }
            })
        })
        .collect();

    let readers: Vec<_> = (0..3)
        .map(|reader| {
            let db = db.clone();
            thread::spawn(move || {
                for _ in 0..40 {
                    let rows = query_rows(
                        &db,
                        (reader + 200) as ClientId,
                        "select id from items where id >= 0 order by id limit 20",
                    );
                    let ids = rows
                        .into_iter()
                        .map(|row| match &row[0] {
                            Value::Int32(v) => *v,
                            other => panic!("expected int row, got {:?}", other),
                        })
                        .collect::<Vec<_>>();
                    assert!(
                        ids.windows(2).all(|w| w[0] <= w[1]),
                        "range scan returned unsorted ids: {ids:?}"
                    );
                }
            })
        })
        .collect();

    join_all_with_timeout(writers, HEAVY_CONTENTION_TEST_TIMEOUT);
    join_all_with_timeout(readers, HEAVY_CONTENTION_TEST_TIMEOUT);

    assert_explain_uses_index(
        &db,
        1,
        "select id from items where id >= 0 order by id limit 20",
        "items_id_idx",
    );
    assert_eq!(
        query_rows(&db, 1, "select count(*) from items"),
        vec![vec![Value::Int64(480)]]
    );
    assert_eq!(
        query_rows(&db, 1, "select note from items where id = 30042"),
        vec![vec![Value::Text("w3-42".into())]]
    );
}

#[test]
fn concurrent_unique_index_inserts_only_allow_one_live_key() {
    let base = temp_dir("concurrent_unique_index_inserts_only_allow_one_live_key");
    let db = Database::open(&base, 64).unwrap();

    db.execute(1, "create table items (id int4, note text)")
        .unwrap();
    db.execute(1, "create unique index items_id_key on items (id)")
        .unwrap();

    let handles: Vec<_> = (0..8)
        .map(|worker| {
            let db = db.clone();
            thread::spawn(move || {
                db.execute(
                    (worker + 300) as ClientId,
                    &format!("insert into items values (1, 'worker{worker}')"),
                )
            })
        })
        .collect();

    let mut successes = 0usize;
    let mut violations = 0usize;
    for handle in handles {
        match handle.join().unwrap() {
            Ok(StatementResult::AffectedRows(1)) => successes += 1,
            Err(ExecError::UniqueViolation { constraint, .. }) => {
                assert_eq!(constraint, "items_id_key");
                violations += 1;
            }
            other => panic!("unexpected concurrent insert result: {:?}", other),
        }
    }

    assert_eq!(successes, 1, "expected one successful insert");
    assert_eq!(violations, 7, "expected seven unique violations");
    assert_eq!(
        query_rows(&db, 1, "select count(*) from items where id = 1"),
        vec![vec![Value::Int64(1)]]
    );
    assert_explain_uses_index(
        &db,
        1,
        "select note from items where id = 1",
        "items_id_key",
    );
}

#[test]
fn concurrent_indexed_updates_and_deletes_keep_index_results_correct() {
    let base = temp_dir("concurrent_indexed_updates_and_deletes_keep_index_results_correct");
    let db = Database::open(&base, 128).unwrap();

    db.execute(1, "create table items (id int4 not null, note text)")
        .unwrap();
    for i in 0..120 {
        db.execute(1, &format!("insert into items values ({i}, 'row{i}')"))
            .unwrap();
    }
    db.execute(1, "create index items_id_idx on items (id)")
        .unwrap();

    let updaters: Vec<_> = (0..3)
        .map(|worker| {
            let db = db.clone();
            thread::spawn(move || {
                for i in 0..20 {
                    let old_id = worker * 20 + i;
                    let new_id = 1000 + worker * 20 + i;
                    db.execute(
                        (worker + 400) as ClientId,
                        &format!(
                            "update items set id = {new_id}, note = 'u{worker}-{i}' where id = {old_id}"
                        ),
                    )
                    .unwrap();
                }
            })
        })
        .collect();

    let deleters: Vec<_> = (0..2)
        .map(|worker| {
            let db = db.clone();
            thread::spawn(move || {
                for i in 0..15 {
                    let id = 60 + worker * 15 + i;
                    db.execute(
                        (worker + 500) as ClientId,
                        &format!("delete from items where id = {id}"),
                    )
                    .unwrap();
                }
            })
        })
        .collect();

    join_all_with_timeout(updaters, HEAVY_CONTENTION_TEST_TIMEOUT);
    join_all_with_timeout(deleters, HEAVY_CONTENTION_TEST_TIMEOUT);

    assert_eq!(
        query_rows(&db, 1, "select count(*) from items"),
        vec![vec![Value::Int64(90)]]
    );
    assert_eq!(
        query_rows(&db, 1, "select note from items where id = 5"),
        Vec::<Vec<Value>>::new()
    );
    assert_eq!(
        query_rows(&db, 1, "select note from items where id = 1005"),
        vec![vec![Value::Text("u0-5".into())]]
    );
    assert_eq!(
        query_rows(&db, 1, "select note from items where id = 74"),
        Vec::<Vec<Value>>::new()
    );
    assert_explain_uses_index(
        &db,
        1,
        "select note from items where id = 1005",
        "items_id_idx",
    );
    assert_explain_uses_index(
        &db,
        1,
        "select note from items where id = 74",
        "items_id_idx",
    );
}

#[test]
fn concurrent_btree_splits_complete_once() {
    #[cfg(debug_assertions)]
    pgrust_access::nbtree::set_btree_split_pause_for_tests(5);
    struct ResetBtreeSplitPause;
    impl Drop for ResetBtreeSplitPause {
        fn drop(&mut self) {
            #[cfg(debug_assertions)]
            pgrust_access::nbtree::set_btree_split_pause_for_tests(0);
        }
    }
    let _reset_pause = ResetBtreeSplitPause;

    let base = temp_dir("concurrent_btree_splits_complete_once");
    let db = Database::open(&base, 128).unwrap();
    db.execute(
        1,
        "create table split_items (id int4 not null, note text not null)",
    )
    .unwrap();
    db.execute(
        1,
        "create index split_items_idx on split_items (id, note) with (fillfactor = 10)",
    )
    .unwrap();

    let workers: Vec<_> = (0..4)
        .map(|worker| {
            let db = db.clone();
            thread::spawn(move || {
                for i in 0..60 {
                    let id = worker * 1000 + i;
                    let note = format!("worker{worker}-{i}-{}", "x".repeat(1400));
                    db.execute(
                        (worker + 700) as ClientId,
                        &format!("insert into split_items values ({id}, '{note}')"),
                    )
                    .unwrap();
                }
            })
        })
        .collect();
    join_all_with_timeout(workers, HEAVY_CONTENTION_TEST_TIMEOUT);

    assert_eq!(
        query_rows(&db, 1, "select count(*) from split_items"),
        vec![vec![Value::Int64(240)]]
    );
    assert_explain_uses_index(
        &db,
        1,
        "select note from split_items where id = 1005",
        "split_items_idx",
    );
    assert_eq!(
        query_rows(&db, 1, "select count(*) from split_items where id >= 0"),
        vec![vec![Value::Int64(240)]]
    );
}

