#[test]
fn create_operator_class_persists_catalog_rows() {
    let base = temp_dir("create_operator_class_rows");
    let db = Database::open(&base, 16).unwrap();

    db.execute(
        1,
        "create function part_hashint4_noop(value int4, seed int8) returns int8 as $$ select value + seed; $$ language sql strict immutable parallel safe",
    )
    .unwrap();
    db.execute(
        1,
        "create operator class part_test_int4_ops for type int4 using hash as operator 1 =, function 2 part_hashint4_noop(int4, int8)",
    )
    .unwrap();

    match db
        .execute(
            1,
            "select opcname, opcintype, opcdefault from pg_opclass where opcname = 'part_test_int4_ops'",
        )
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(
                rows,
                vec![vec![
                    Value::Text("part_test_int4_ops".into()),
                    Value::Int64(i64::from(crate::include::catalog::INT4_TYPE_OID)),
                    Value::Bool(false),
                ]]
            );
        }
        other => panic!("expected query result, got {:?}", other),
    }

    match db
        .execute(
            1,
            "select amopstrategy, amprocnum from pg_opclass c join pg_amop o on o.amopfamily = c.opcfamily join pg_amproc p on p.amprocfamily = c.opcfamily where c.opcname = 'part_test_int4_ops'",
        )
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int16(1), Value::Int16(2)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }

    db.execute(1, "drop operator class part_test_int4_ops using hash")
        .unwrap();
    match db
        .execute(
            1,
            "select count(*) from pg_opclass where opcname = 'part_test_int4_ops'",
        )
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int64(0)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }
}

#[test]
fn create_operator_class_uses_schema_qualified_composite_operator() {
    let base = temp_dir("create_operator_class_composite_operator");
    let db = Database::open(&base, 16).unwrap();

    db.execute(1, "create schema alter1").unwrap();
    db.execute(1, "create type alter1.ctype as (f1 int, f2 text)")
        .unwrap();
    db.execute(
        1,
        "create function alter1.same(alter1.ctype, alter1.ctype) returns boolean language sql as $$
         select $1.f1 is not distinct from $2.f1 and $1.f2 is not distinct from $2.f2
         $$",
    )
    .unwrap();
    db.execute(
        1,
        "create operator alter1.=(procedure = alter1.same, leftarg = alter1.ctype, rightarg = alter1.ctype)",
    )
    .unwrap();
    db.execute(
        1,
        "create operator class alter1.ctype_hash_ops default for type alter1.ctype using hash as
         operator 1 alter1.=(alter1.ctype, alter1.ctype)",
    )
    .unwrap();

    assert_eq!(
        query_rows(
            &db,
            1,
            "select o.oprname, c.opcname, c.opcdefault
             from pg_operator o
             join pg_amop a on a.amopopr = o.oid
             join pg_opclass c on c.opcfamily = a.amopfamily
             join pg_namespace n on n.oid = c.opcnamespace
             where n.nspname = 'alter1' and c.opcname = 'ctype_hash_ops'",
        ),
        vec![vec![
            Value::Text("=".into()),
            Value::Text("ctype_hash_ops".into()),
            Value::Bool(true),
        ]]
    );
}

