#[test]
fn create_operator_enforces_type_and_function_acl() {
    let db = Database::open_ephemeral(16).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create role regress_rol_op_acl")
        .unwrap();
    session
        .execute(
            &db,
            "create type type_op_acl as enum ('new', 'open', 'closed')",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create function fn_op_acl(int8, int8) returns type_op_acl language sql immutable as $$ select null::type_op_acl $$",
        )
        .unwrap();
    session
        .execute(&db, "revoke usage on type type_op_acl from public")
        .unwrap();
    session
        .execute(
            &db,
            "revoke execute on function fn_op_acl(int8, int8) from public",
        )
        .unwrap();
    session.execute(&db, "set role regress_rol_op_acl").unwrap();

    match session.execute(
        &db,
        "create operator #*# (leftarg = int8, rightarg = int8, procedure = fn_op_acl)",
    ) {
        Err(ExecError::DetailedError { message, .. }) => {
            assert!(message.starts_with("permission denied for "));
        }
        other => panic!("expected ACL failure, got {:?}", other),
    }
}

#[test]
fn create_operator_negator_and_commutator_errors_match_postgres() {
    let db = Database::open_ephemeral(16).unwrap();

    match db.execute(
        1,
        "create operator === (leftarg = integer, rightarg = integer, procedure = int4eq, negator = ===)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError { message, .. })) => {
            assert_eq!(message, "operator cannot be its own negator");
        }
        other => panic!("expected self-negator error, got {:?}", other),
    }

    let db = Database::open_ephemeral(16).unwrap();
    db.execute(
        1,
        "create operator === (leftarg = integer, rightarg = integer, procedure = int4eq, commutator = ===!!!)",
    )
    .unwrap();
    match db.execute(
        1,
        "create operator ===!!! (leftarg = integer, rightarg = integer, procedure = int4ne, negator = ===!!!)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError { message, .. })) => {
            assert_eq!(message, "operator cannot be its own negator");
        }
        other => panic!("expected shell replacement self-negator error, got {:?}", other),
    }

    let db = Database::open_ephemeral(16).unwrap();
    match db.execute(
        1,
        "create operator === (leftarg = integer, rightarg = integer, procedure = int4eq, commutator = =)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError { message, .. })) => {
            assert_eq!(
                message,
                "commutator operator = is already the commutator of operator ="
            );
        }
        other => panic!("expected commutator pair error, got {:?}", other),
    }

    let db = Database::open_ephemeral(16).unwrap();
    match db.execute(
        1,
        "create operator === (leftarg = integer, rightarg = integer, procedure = int4eq, negator = <>)",
    ) {
        Err(ExecError::Parse(ParseError::DetailedError { message, .. })) => {
            assert_eq!(message, "negator operator <> is already the negator of operator =");
        }
        other => panic!("expected negator pair error, got {:?}", other),
    }
}

#[test]
fn copy_from_rows_respects_active_transaction() {
    let base = temp_dir("copy_from_rows_txn");
    let db = Database::open(&base, 16).unwrap();
    let mut writer = Session::new(1);
    let mut reader = Session::new(2);

    db.execute(
            1,
            "create table pgbench_tellers (tid int not null, bid int not null, tbalance int not null, filler text)",
        )
        .unwrap();

    writer.execute(&db, "begin").unwrap();
    let inserted = writer
        .copy_from_rows(
            &db,
            "pgbench_tellers",
            &[vec!["10".into(), "1".into(), "0".into(), "\\N".into()]],
        )
        .unwrap();
    assert_eq!(inserted, 1);

    match reader
        .execute(&db, "select count(*) from pgbench_tellers")
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int64(0)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }

    writer.execute(&db, "commit").unwrap();

    match reader
        .execute(
            &db,
            "select tid, bid, tbalance, filler from pgbench_tellers",
        )
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(
                rows,
                vec![vec![
                    Value::Int32(10),
                    Value::Int32(1),
                    Value::Int32(0),
                    Value::Null,
                ]]
            );
        }
        other => panic!("expected query result, got {:?}", other),
    }
}

#[test]
fn copy_from_rows_parses_array_literals() {
    let base = temp_dir("copy_from_rows_arrays");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    db.execute(
        1,
        "create table records (id int not null, tags varchar[], sizes int4[])",
    )
    .unwrap();

    let inserted = session
        .copy_from_rows(
            &db,
            "records",
            &[vec![
                "1".into(),
                "{\"a\",\"b\"}".into(),
                "{1,NULL,3}".into(),
            ]],
        )
        .unwrap();
    assert_eq!(inserted, 1);

    match db
        .execute(1, "select id, tags, sizes from records")
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(
                rows,
                vec![vec![
                    Value::Int32(1),
                    Value::PgArray(
                        crate::include::nodes::datum::ArrayValue::from_1d(vec![
                            Value::Text("a".into()),
                            Value::Text("b".into()),
                        ])
                        .with_element_type_oid(crate::include::catalog::VARCHAR_TYPE_OID),
                    ),
                    Value::PgArray(
                        crate::include::nodes::datum::ArrayValue::from_1d(vec![
                            Value::Int32(1),
                            Value::Null,
                            Value::Int32(3),
                        ])
                        .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
                    ),
                ]]
            );
        }
        other => panic!("expected query result, got {:?}", other),
    }
}

#[test]
fn copy_from_rows_parses_quoted_array_text_and_empty_arrays() {
    let base = temp_dir("copy_from_rows_arrays_quoted");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    db.execute(
        1,
        "create table records (id int not null, tags varchar[], sizes int4[])",
    )
    .unwrap();

    session
        .copy_from_rows(
            &db,
            "records",
            &[
                vec!["1".into(), "{\"a,b\",\"c\\\"d\"}".into(), "{}".into()],
                vec!["2".into(), "{}".into(), "{NULL}".into()],
            ],
        )
        .unwrap();

    match db
        .execute(1, "select id, tags, sizes from records order by id")
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(
                rows,
                vec![
                    vec![
                        Value::Int32(1),
                        Value::PgArray(
                            crate::include::nodes::datum::ArrayValue::from_1d(vec![
                                Value::Text("a,b".into()),
                                Value::Text("c\"d".into()),
                            ])
                            .with_element_type_oid(crate::include::catalog::VARCHAR_TYPE_OID),
                        ),
                        Value::PgArray(
                            crate::include::nodes::datum::ArrayValue::empty()
                                .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
                        ),
                    ],
                    vec![
                        Value::Int32(2),
                        Value::PgArray(
                            crate::include::nodes::datum::ArrayValue::empty()
                                .with_element_type_oid(crate::include::catalog::VARCHAR_TYPE_OID),
                        ),
                        Value::PgArray(
                            crate::include::nodes::datum::ArrayValue::from_1d(vec![Value::Null])
                                .with_element_type_oid(crate::include::catalog::INT4_TYPE_OID),
                        ),
                    ],
                ]
            );
        }
        other => panic!("expected query result, got {:?}", other),
    }
}

#[test]
fn temp_tables_are_session_local_and_mask_permanent_tables() {
    let base = temp_dir("temp_table_masking");
    let db = Database::open(&base, 16).unwrap();
    let mut session_a = Session::new(1);
    let mut session_b = Session::new(2);

    db.execute(1, "create table items (id int4 not null)")
        .unwrap();
    db.execute(1, "insert into items (id) values (1)").unwrap();

    session_a
        .execute(&db, "create temp table items (id int4 not null)")
        .unwrap();
    let catalog = session_a.catalog_lookup(&db);
    let unqualified = catalog.lookup_any_relation("items").unwrap();
    let qualified = catalog.lookup_any_relation("public.items").unwrap();
    assert_ne!(unqualified.rel, qualified.rel);
    session_a
        .execute(&db, "insert into items (id) values (2)")
        .unwrap();

    match session_a.execute(&db, "select id from items").unwrap() {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int32(2)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }

    match session_b.execute(&db, "select id from items").unwrap() {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int32(1)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }

    session_a.execute(&db, "drop table items").unwrap();
    match session_a.execute(&db, "select id from items").unwrap() {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int32(1)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }

    match session_a
        .execute(&db, "select id from public.items")
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int32(1)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }
}

#[test]
fn drop_table_supports_qualified_public_name_under_temp_shadowing() {
    let base = temp_dir("drop_table_public_under_temp_shadow");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    db.execute(1, "create table items (id int4 not null)")
        .unwrap();
    db.execute(1, "insert into items (id) values (1)").unwrap();
    session
        .execute(&db, "create temp table items (id int4 not null)")
        .unwrap();
    session
        .execute(&db, "insert into items (id) values (2)")
        .unwrap();

    session.execute(&db, "drop table public.items").unwrap();

    match session.execute(&db, "select id from items").unwrap() {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int32(2)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }

    let err = session
        .execute(&db, "select id from public.items")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::Parse(ParseError::UnknownTable(name)) if name == "public.items"
    ));
}

