#[test]
fn create_function_uses_search_path_for_unqualified_creation() {
    let base = temp_dir("search_path_function_create");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session.execute(&db, "create schema tenant_fn").unwrap();
    session.execute(&db, "set search_path = tenant_fn").unwrap();
    session
        .execute(
            &db,
            "create function add_one(x int4) returns int4 language sql as $$ select x + 1 $$",
        )
        .unwrap();

    let visible = db.backend_catcache(1, None).unwrap();
    let proc = visible
        .proc_rows_by_name("add_one")
        .into_iter()
        .find(|row| row.proname == "add_one")
        .expect("function row");
    let tenant_ns = visible
        .namespace_by_name("tenant_fn")
        .expect("tenant namespace")
        .oid;
    assert_eq!(proc.pronamespace, tenant_ns);
}

#[test]
fn alter_function_uses_search_path_for_unqualified_resolution() {
    let base = temp_dir("search_path_function_alter");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session.execute(&db, "create schema fn_first").unwrap();
    session.execute(&db, "create schema fn_second").unwrap();
    session
        .execute(&db, "set search_path = fn_first, fn_second, public")
        .unwrap();
    session
        .execute(
            &db,
            "create function pick_me(x int4) returns int4 language sql as $$ select x + 1 $$",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create function fn_second.pick_me(x int4) returns int4 language sql as $$ select x + 2 $$",
        )
        .unwrap();

    session
        .execute(&db, "alter function pick_me(int4) rename to picked_first")
        .unwrap();

    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "select n.nspname, p.proname \
             from pg_proc p join pg_namespace n on n.oid = p.pronamespace \
             where n.nspname in ('fn_first', 'fn_second') \
             order by n.nspname, p.proname",
        ),
        vec![
            vec![
                Value::Text("fn_first".into()),
                Value::Text("picked_first".into())
            ],
            vec![
                Value::Text("fn_second".into()),
                Value::Text("pick_me".into())
            ],
        ]
    );
}

