#[test]
fn pg_temp_function_drop_and_operator_create_reject_prepare() {
    let base = temp_dir("pg_temp_prepare_touch_namespace");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create function pg_temp.twophase_func() returns void language sql as $$ select '2pc_func'::text $$",
        )
        .unwrap();

    session.execute(&db, "begin").unwrap();
    session
        .execute(&db, "drop function pg_temp.twophase_func()")
        .unwrap();
    let err = session
        .execute(&db, "prepare transaction 'twophase_func'")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::DetailedError { message, .. }
            if message == "cannot PREPARE a transaction that has operated on temporary objects"
    ));
    assert!(!session.in_transaction());

    session.execute(&db, "begin").unwrap();
    session
        .execute(
            &db,
            "create operator pg_temp.@@ (leftarg = int4, rightarg = int4, procedure = int4mi)",
        )
        .unwrap();
    let err = session
        .execute(&db, "prepare transaction 'twophase_operator'")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::DetailedError { message, .. }
            if message == "cannot PREPARE a transaction that has operated on temporary objects"
    ));

    session.execute(&db, "begin").unwrap();
    session
        .execute(&db, "create type pg_temp.twophase_type as (a int4)")
        .unwrap();
    let err = session
        .execute(&db, "prepare transaction 'twophase_type'")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::DetailedError { message, .. }
            if message == "cannot PREPARE a transaction that has operated on temporary objects"
    ));

    session.execute(&db, "begin").unwrap();
    session
        .execute(&db, "create view pg_temp.twophase_view as select 1")
        .unwrap();
    let err = session
        .execute(&db, "prepare transaction 'twophase_view'")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::DetailedError { message, .. }
            if message == "cannot PREPARE a transaction that has operated on temporary objects"
    ));
}

#[test]
fn temp_relation_access_rejects_prepare_transaction() {
    let base = temp_dir("temp_relation_access_prepare");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "create temp table twophase_tab (a int4)")
        .unwrap();

    for (sql, gid) in [
        ("select a from twophase_tab", "twophase_select"),
        ("insert into twophase_tab values (1)", "twophase_insert"),
        (
            "lock twophase_tab in access exclusive mode",
            "twophase_lock",
        ),
        (
            "declare twophase_cur cursor for select a from twophase_tab",
            "twophase_cursor",
        ),
        ("drop table twophase_tab", "twophase_drop"),
    ] {
        session.execute(&db, "begin").unwrap();
        session.execute(&db, sql).unwrap();
        let err = session
            .execute(&db, &format!("prepare transaction '{gid}'"))
            .unwrap_err();
        assert!(matches!(
            err,
            ExecError::DetailedError { message, .. }
                if message == "cannot PREPARE a transaction that has operated on temporary objects"
        ));
        assert!(!session.in_transaction());
    }
}

