#[test]
fn temp_namespace_reuse_cleans_stale_relations_before_create_table_lowering() {
    let base = temp_dir("temp_cleanup_before_create_lowering");
    {
        let db = Database::open(&base, 16).unwrap();
        let mut first_session = Session::with_temp_backend_id(10, 1);

        first_session
            .execute(&db, "create temp table point_tbl (f1 point)")
            .unwrap();
        first_session
            .execute(&db, "create index gpointind on point_tbl using gist (f1)")
            .unwrap();
        first_session
            .execute(&db, "create temp table gpolygon_tbl (f1 polygon)")
            .unwrap();
        first_session
            .execute(
                &db,
                "create index ggpolygonind on gpolygon_tbl using gist (f1)",
            )
            .unwrap();
        first_session
            .execute(
                &db,
                "create temp table boolindex (b bool, i int, unique(b, i), junk float)",
            )
            .unwrap();
        first_session
            .execute(&db, "create temp table concur_temp_tab_3 (c1 int, c2 text)")
            .unwrap();
        first_session
            .execute(
                &db,
                "create index concur_temp_ind_3 on concur_temp_tab_3(c2)",
            )
            .unwrap();
        // Simulate a backend/process exit before temp cleanup. The next user
        // of this temp slot must clean these catalog rows before CREATE TABLE
        // performs relation/type lookups.
    }

    let db = Database::open(&base, 16).unwrap();
    let mut reused_session = Session::with_temp_backend_id(11, 1);
    reused_session
        .execute(
            &db,
            "create temporary table empsalary (
                depname varchar,
                empno bigint,
                salary int,
                enroll_date date
            )",
        )
        .unwrap();
    match reused_session
        .execute(
            &db,
            "select count(*) from pg_class
             where relpersistence = 't'
               and relname in (
                   'point_tbl',
                   'gpointind',
                   'gpolygon_tbl',
                   'ggpolygonind',
                   'boolindex',
                   'concur_temp_tab_3',
                   'concur_temp_ind_3'
               )",
        )
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(rows, vec![vec![Value::Int64(0)]]);
        }
        other => panic!("expected query result, got {:?}", other),
    }
    reused_session
        .execute(
            &db,
            "insert into empsalary values ('develop', 10, 5200, '2007-08-01')",
        )
        .unwrap();

    match reused_session
        .execute(&db, "select depname, empno, salary from empsalary")
        .unwrap()
    {
        StatementResult::Query { rows, .. } => {
            assert_eq!(
                rows,
                vec![vec![
                    Value::Text("develop".into()),
                    Value::Int64(10),
                    Value::Int32(5200),
                ]]
            );
        }
        other => panic!("expected query result, got {:?}", other),
    }
}

#[test]
fn temp_namespace_creation_does_not_poison_global_next_oid() {
    let base = temp_dir("temp_namespace_next_oid");
    let db = Database::open(&base, 16).unwrap();
    let mut session = Session::with_temp_backend_id(1, 7);

    let initial_next_oid = db.catalog.read().catalog_snapshot().unwrap().next_oid;
    assert!(initial_next_oid < Database::temp_namespace_oid(7));

    session
        .execute(&db, "create temp table temp_probe (id int4)")
        .unwrap();

    let catalog = db.catalog.read().catalog_snapshot().unwrap();
    let temp_entry = db.temp_entry(1, "temp_probe").unwrap();
    assert!(
        catalog.next_oid < Database::temp_namespace_oid(7),
        "next_oid jumped into reserved temp namespace range: {}",
        catalog.next_oid
    );
    assert!(
        temp_entry.relation_oid < Database::temp_namespace_oid(7),
        "temp relation oid jumped into reserved temp namespace range: {}",
        temp_entry.relation_oid
    );
}

