#[test]
fn create_function_defaults_and_named_calls_work() {
    let dir = temp_dir("create_function_defaults_named");
    let db = Database::open(&dir, 64).unwrap();

    db.execute(
        1,
        "create function dfunc(a int4 = 1, b int4 = 2) returns int4 language sql as $$ select $1 + $2 $$",
    )
    .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select dfunc(), dfunc(10), dfunc(10, 20)"),
        vec![vec![Value::Int32(3), Value::Int32(12), Value::Int32(30)]]
    );
    assert_eq!(
        query_rows(&db, 1, "select dfunc(a := 7), dfunc(b => 11, a => 4)"),
        vec![vec![Value::Int32(9), Value::Int32(15)]]
    );

    db.execute(
        1,
        "create function choose_text(a text, b text default 'fallback', flag bool default true) returns text language sql as $$ select case when $3 then $1 else $2 end $$",
    )
    .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select choose_text('a'), choose_text('a', 'b', flag := false), choose_text(b => 'b', a => 'a')",
        ),
        vec![vec![
            Value::Text("a".into()),
            Value::Text("b".into()),
            Value::Text("a".into()),
        ]]
    );

    db.execute(
        1,
        "create function default_series(a int4 default 1, b int4 default 2) returns setof int4 language sql as $$ values ($1), ($2) $$",
    )
    .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select * from default_series(b => 5)"),
        vec![vec![Value::Int32(1)], vec![Value::Int32(5)]]
    );
    assert_eq!(
        query_rows(&db, 1, "select * from default_series()"),
        vec![vec![Value::Int32(1)], vec![Value::Int32(2)]]
    );

    match db.execute(1, "select choose_text(a => 'a', a => 'b')") {
        Err(ExecError::Parse(ParseError::DetailedError { message, .. }))
            if message == "argument name \"a\" used more than once" => {}
        other => panic!("expected duplicate named argument error, got {other:?}"),
    }
}

#[test]
fn create_sql_function_window_frames_keep_unbounded_keyword() {
    let dir = temp_dir("create_function_window_frames");
    let db = Database::open(&dir, 64).unwrap();

    db.execute(
        1,
        "create function frame_arg(x int4) returns table (a int4, b int4, c int4)
         language sql
         begin atomic
           select sum(v) over (order by v rows between x preceding and x following), v, g
           from (values (1, 0), (2, 0), (3, 1), (4, 1)) s(v, g)
           order by v;
         end",
    )
    .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select * from frame_arg(1)"),
        vec![
            vec![Value::Int32(3), Value::Int32(1), Value::Int32(0)],
            vec![Value::Int32(6), Value::Int32(2), Value::Int32(0)],
            vec![Value::Int32(9), Value::Int32(3), Value::Int32(1)],
            vec![Value::Int32(7), Value::Int32(4), Value::Int32(1)],
        ]
    );

    db.execute(
        1,
        "create function frame_unbounded(unbounded int4) returns table (a int4, b int4, c int4)
         language sql
         begin atomic
           select sum(v) over (
                    order by v rows between unbounded preceding and unbounded following
                  ),
                  v,
                  g
           from (values (1, 0), (2, 0), (3, 1), (4, 1)) s(v, g)
           order by v;
         end",
    )
    .unwrap();
    assert_eq!(
        query_rows(&db, 1, "select * from frame_unbounded(99)"),
        vec![
            vec![Value::Int32(10), Value::Int32(1), Value::Int32(0)],
            vec![Value::Int32(10), Value::Int32(2), Value::Int32(0)],
            vec![Value::Int32(10), Value::Int32(3), Value::Int32(1)],
            vec![Value::Int32(10), Value::Int32(4), Value::Int32(1)],
        ]
    );
}

