#[test]
fn partitioned_on_conflict_do_update_subquery() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut session = Session::new(1);

    session
        .execute(
            &db,
            "create table upsert_test (a int primary key, b text) partition by list (a)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "create table upsert_test_1 partition of upsert_test for values in (1)",
        )
        .unwrap();
    session
        .execute(&db, "insert into upsert_test values (1, 'Boo')")
        .unwrap();

    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "with aaa as (select 1 as a, 'Foo' as b)
             insert into upsert_test values (1, 'Bar')
             on conflict(a) do update set (b, a) = (select b, a from aaa)
             returning a, b",
        ),
        vec![vec![Value::Int32(1), Value::Text("Foo".into())]]
    );

    session
        .execute(
            &db,
            "create table upsert_test_2 (b text, a int primary key)",
        )
        .unwrap();
    session
        .execute(
            &db,
            "alter table upsert_test attach partition upsert_test_2 for values in (2)",
        )
        .unwrap();
    session
        .execute(&db, "insert into upsert_test_2(b, a) values ('Zoo', 2)")
        .unwrap();

    assert_eq!(
        session_query_rows(
            &mut session,
            &db,
            "with aaa as (select 1 as ctea, ' Foo' as cteb)
             insert into upsert_test values (1, 'Bar'), (2, 'Baz')
             on conflict(a) do update
                set b = (select upsert_test.b || cteb from aaa),
                    a = (select upsert_test.a from aaa)
             returning a, b",
        ),
        vec![
            vec![Value::Int32(1), Value::Text("Foo Foo".into())],
            vec![Value::Int32(2), Value::Text("Zoo Foo".into())],
        ]
    );
    assert_eq!(
        session_query_rows(&mut session, &db, "select a, b from upsert_test order by a"),
        vec![
            vec![Value::Int32(1), Value::Text("Foo Foo".into())],
            vec![Value::Int32(2), Value::Text("Zoo Foo".into())],
        ]
    );
}

#[test]
fn rls_policy_subquery_privileges_are_checked_for_select_and_explain() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    let mut owner = Session::new(1);
    let mut app = Session::new(2);

    owner
        .execute(&db, "create role policy_owner nologin")
        .unwrap();
    owner
        .execute(&db, "create role policy_app nologin")
        .unwrap();
    owner
        .execute(&db, "set session authorization policy_owner")
        .unwrap();
    owner
        .execute(&db, "create table visible_docs (a int4)")
        .unwrap();
    owner
        .execute(&db, "create table hidden_docs (a int4)")
        .unwrap();
    owner
        .execute(&db, "insert into visible_docs values (1), (2)")
        .unwrap();
    owner
        .execute(&db, "insert into hidden_docs values (1)")
        .unwrap();
    owner
        .execute(&db, "grant select on visible_docs to policy_app")
        .unwrap();
    owner
        .execute(
            &db,
            "create policy visible_policy on visible_docs for select to policy_app
             using (not exists (select 1 from hidden_docs h where h.a = visible_docs.a))",
        )
        .unwrap();
    owner
        .execute(&db, "alter table visible_docs enable row level security")
        .unwrap();

    app.execute(&db, "set session authorization policy_app")
        .unwrap();
    let err = app.execute(&db, "select * from visible_docs").unwrap_err();
    assert_sqlstate(err, "42501", "permission denied for table hidden_docs");
    let err = app
        .execute(&db, "explain (costs off) select * from visible_docs")
        .unwrap_err();
    assert_sqlstate(err, "42501", "permission denied for table hidden_docs");
}

