#[test]
fn nested_cte_survives_plpgsql_internal_select() {
    let dir = temp_dir("nested_cte_plpgsql_internal_select");
    let db = Database::open(&dir, 64).unwrap();
    let mut session = Session::new(1);

    session
        .execute(&db, "set statement_timeout = '2s'")
        .unwrap();
    session
        .execute(&db, "create table cte_inputs(i int4 primary key)")
        .unwrap();
    session
        .execute(&db, "insert into cte_inputs values (1), (2)")
        .unwrap();
    session
        .execute(
            &db,
            "create function plpgsql_select_identity(x int4) returns int4 language plpgsql as $$
             declare y int4;
             begin
               select x into y;
               return y;
             end;
             $$",
        )
        .unwrap();

    let rows = session_query_rows(
        &mut session,
        &db,
        "with test_bytes as (
           select i, plpgsql_select_identity(i) as v from cte_inputs
         ), test_padded as (
           select i, plpgsql_select_identity(v + 100) as v from test_bytes
         )
         select p.i, b.v, p.v
         from test_padded p
         join test_bytes b using (i)
         order by p.i",
    );

    assert_eq!(
        rows,
        vec![
            vec![Value::Int32(1), Value::Int32(1), Value::Int32(101)],
            vec![Value::Int32(2), Value::Int32(2), Value::Int32(102)],
        ]
    );
}

#[test]
fn recursive_cte_search_depth_first_executes() {
    let dir = temp_dir("recursive_cte_search_depth");
    let db = Database::open(&dir, 64).unwrap();

    db.execute(1, "create table graph0(f int4, t int4, label text)")
        .unwrap();
    db.execute(
        1,
        "insert into graph0 values (1,2,'arc 1 -> 2'), (1,3,'arc 1 -> 3'), (2,3,'arc 2 -> 3')",
    )
    .unwrap();

    let rows = query_rows(
        &db,
        1,
        "with recursive search_graph(f, t, label) as (
            select * from graph0 g
            union all
            select g.* from graph0 g, search_graph sg where g.f = sg.t
        ) search depth first by f, t set seq
        select f, t, label from search_graph order by seq",
    );

    assert_eq!(
        rows,
        vec![
            vec![
                Value::Int32(1),
                Value::Int32(2),
                Value::Text("arc 1 -> 2".into())
            ],
            vec![
                Value::Int32(2),
                Value::Int32(3),
                Value::Text("arc 2 -> 3".into())
            ],
            vec![
                Value::Int32(1),
                Value::Int32(3),
                Value::Text("arc 1 -> 3".into())
            ],
            vec![
                Value::Int32(2),
                Value::Int32(3),
                Value::Text("arc 2 -> 3".into())
            ],
        ]
    );
}

