#[test]
fn session_user_and_current_role_are_sql_visible() {
    let dir = temp_dir("session_user_current_role");
    let db = Database::open(&dir, 64).unwrap();

    db.execute(1, "create role tenant login").unwrap();
    db.execute(1, "create role manager").unwrap();
    db.execute(1, "grant manager to tenant").unwrap();
    db.execute(1, "set session authorization tenant").unwrap();

    match db
        .execute(
            1,
            "select session_user, current_role, current_user, current_setting('role') as role",
        )
        .unwrap()
    {
        StatementResult::Query { column_names, .. } => assert_eq!(
            column_names,
            vec!["session_user", "current_role", "current_user", "role"]
        ),
        other => panic!("expected query result, got {other:?}"),
    }

    assert_eq!(
        query_rows(&db, 1, "select session_user, current_user, current_role"),
        vec![vec![
            Value::Text("tenant".into()),
            Value::Text("tenant".into()),
            Value::Text("tenant".into()),
        ]]
    );
    assert_eq!(
        query_rows(&db, 1, "select current_setting('role')"),
        vec![vec![Value::Text("none".into())]]
    );
    assert_eq!(
        query_rows(&db, 1, "select current_setting('session_authorization')"),
        vec![vec![Value::Text("tenant".into())]]
    );

    db.execute(1, "set role manager").unwrap();

    assert_eq!(
        query_rows(&db, 1, "select session_user, current_user, current_role"),
        vec![vec![
            Value::Text("tenant".into()),
            Value::Text("manager".into()),
            Value::Text("manager".into()),
        ]]
    );
    assert_eq!(
        query_rows(&db, 1, "select current_setting('role')"),
        vec![vec![Value::Text("manager".into())]]
    );

    db.execute(1, "reset role").unwrap();
    assert_eq!(
        query_rows(&db, 1, "select current_setting('role')"),
        vec![vec![Value::Text("none".into())]]
    );
}

#[test]
fn sql_function_set_role_option_changes_identity_temporarily() {
    let db = Database::open_ephemeral(32).unwrap();

    db.execute(1, "create role caller login").unwrap();
    db.execute(1, "create role worker").unwrap();
    db.execute(1, "grant worker to caller").unwrap();
    db.execute(
        1,
        "create function report_set_role() returns text
         language sql
         set role = worker
         as $$ select current_user || ':' || current_setting('role') || ':' || session_user $$",
    )
    .unwrap();
    db.execute(
        1,
        "create function set_role_and_error(int4) returns int4
         language sql
         set role = worker
         as $$ select 1 / $1 $$",
    )
    .unwrap();

    db.execute(1, "set session authorization caller").unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select report_set_role(), current_user, current_setting('role')",
        ),
        vec![vec![
            Value::Text("worker:worker:caller".into()),
            Value::Text("caller".into()),
            Value::Text("none".into()),
        ]]
    );

    assert!(db.execute(1, "select set_role_and_error(0)").is_err());
    assert_eq!(
        query_rows(&db, 1, "select current_user, current_setting('role')"),
        vec![vec![
            Value::Text("caller".into()),
            Value::Text("none".into()),
        ]]
    );
}

