#[test]
fn delete_prepared_insert_and_copy_from_fire_triggers() {
    let dir = temp_dir("trigger_delete_prepared_copy");
    let db = Database::open(&dir, 64).unwrap();
    let mut session = Session::new(1);

    db.execute(1, "create table items (id int4, note text)")
        .unwrap();
    db.execute(
        1,
        "create function before_insert_notice() returns trigger language plpgsql as $$ begin raise notice 'insert:%', NEW.id; NEW.note := NEW.note || '-ok'; return NEW; end $$",
    )
    .unwrap();
    db.execute(
        1,
        "create function before_delete_notice() returns trigger language plpgsql as $$ begin if OLD.id = 2 then return null; end if; raise notice 'delete:%', OLD.id; return OLD; end $$",
    )
    .unwrap();
    db.execute(
        1,
        "create trigger items_before_insert before insert on items for each row execute function before_insert_notice()",
    )
    .unwrap();
    db.execute(
        1,
        "create trigger items_before_delete before delete on items for each row execute function before_delete_notice()",
    )
    .unwrap();

    let prepared = session.prepare_insert(&db, "items", None, 2).unwrap();
    session.execute(&db, "begin").unwrap();
    clear_notices();
    session
        .execute_prepared_insert(
            &db,
            &prepared,
            &[Value::Int32(1), Value::Text("prepared".into())],
        )
        .unwrap();
    session.execute(&db, "commit").unwrap();
    assert_eq!(take_notice_messages(), vec!["insert:1".to_string()]);

    clear_notices();
    session
        .copy_from_rows(
            &db,
            "items",
            &[
                vec!["2".into(), "copied".into()],
                vec!["3".into(), "copied".into()],
            ],
        )
        .unwrap();
    assert_eq!(
        take_notice_messages(),
        vec!["insert:2".to_string(), "insert:3".to_string()]
    );
    assert_eq!(
        query_rows(&db, 1, "select id, note from items order by id"),
        vec![
            vec![Value::Int32(1), Value::Text("prepared-ok".into())],
            vec![Value::Int32(2), Value::Text("copied-ok".into())],
            vec![Value::Int32(3), Value::Text("copied-ok".into())],
        ]
    );

    clear_notices();
    db.execute(1, "delete from items where id in (1, 2)")
        .unwrap();
    assert_eq!(take_notice_messages(), vec!["delete:1".to_string()]);
    assert_eq!(
        query_rows(&db, 1, "select id from items order by id"),
        vec![vec![Value::Int32(2)], vec![Value::Int32(3)]]
    );
}

#[test]
fn create_type_exposes_catalog_rows_and_function_row_expansion() {
    let dir = temp_dir("create_type_catalog_rows");
    let db = Database::open(&dir, 64).unwrap();

    db.execute(1, "create type widget as (id int4, label text)")
        .unwrap();
    db.execute(
        1,
        "create function widget_rows(n int4) returns setof widget language plpgsql as $$ begin return query values (n, 'widget'); end $$",
    )
    .unwrap();

    let visible = db.lazy_catalog_lookup(1, None, None);
    let widget_relation = visible.lookup_any_relation("widget").unwrap();
    let widget_type = visible
        .type_rows()
        .into_iter()
        .find(|row| row.typname == "widget")
        .unwrap();
    let widget_proc = visible
        .proc_rows_by_name("widget_rows")
        .into_iter()
        .next()
        .unwrap();

    assert_eq!(widget_relation.relkind, 'c');
    assert_eq!(widget_type.typrelid, widget_relation.relation_oid);
    assert_eq!(widget_proc.prorettype, widget_type.oid);
    assert!(widget_proc.proretset);
    assert_eq!(relfilenode_for(&db, 1, "widget"), 0);
    assert_eq!(
        query_rows(
            &db,
            1,
            &format!(
                "select attname from pg_attribute where attrelid = {} and attnum > 0 order by attnum",
                widget_relation.relation_oid
            ),
        ),
        vec![
            vec![Value::Text("id".into())],
            vec![Value::Text("label".into())],
        ]
    );
    assert!(
        db.backend_catcache(1, None)
            .unwrap()
            .depend_rows()
            .iter()
            .any(|row| {
                row.classid == PG_PROC_RELATION_OID
                    && row.objid == widget_proc.oid
                    && row.refclassid == PG_TYPE_RELATION_OID
                    && row.refobjid == widget_type.oid
            })
    );
    assert_eq!(
        query_rows(&db, 1, "select * from widget_rows(5)"),
        vec![vec![Value::Int32(5), Value::Text("widget".into())]]
    );
}

#[test]
fn typed_table_create_alter_of_and_composite_attribute_cascade() {
    let dir = temp_dir("typed_table_catalog_rows");
    let db = Database::open(&dir, 64).unwrap();

    db.execute(1, "create type person_t as (id int4, name text)")
        .unwrap();
    db.execute(
        1,
        "create table persons of person_t (id with options primary key, name not null default 'unknown')",
    )
    .unwrap();
    db.execute(1, "insert into persons(id) values (1)").unwrap();
    assert_eq!(
        query_rows(&db, 1, "select id, name from persons"),
        vec![vec![Value::Int32(1), Value::Text("unknown".into())]]
    );

    let visible = db.lazy_catalog_lookup(1, None, None);
    let person_type = visible.type_by_name("person_t").unwrap();
    let persons = visible.lookup_any_relation("persons").unwrap();
    assert_eq!(persons.of_type_oid, person_type.oid);
    assert!(
        db.backend_catcache(1, None)
            .unwrap()
            .depend_rows()
            .iter()
            .any(|row| {
                row.classid == PG_CLASS_RELATION_OID
                    && row.objid == persons.relation_oid
                    && row.refclassid == PG_TYPE_RELATION_OID
                    && row.refobjid == person_type.oid
            })
    );
    drop(visible);

    db.execute(1, "alter table persons not of").unwrap();
    assert_eq!(
        db.lazy_catalog_lookup(1, None, None)
            .lookup_any_relation("persons")
            .unwrap()
            .of_type_oid,
        0
    );

    db.execute(1, "alter table persons of person_t").unwrap();
    let err = db
        .execute(1, "alter type person_t drop attribute name restrict")
        .unwrap_err();
    match err {
        ExecError::DetailedError { hint, .. } => {
            assert_eq!(
                hint.as_deref(),
                Some("Use ALTER ... CASCADE to alter the typed tables too.")
            );
        }
        other => panic!("expected dependent typed table error, got {other:?}"),
    }

    db.execute(1, "alter type person_t add attribute age int4 cascade")
        .unwrap();
    let visible = db.lazy_catalog_lookup(1, None, None);
    let persons = visible.lookup_any_relation("persons").unwrap();
    assert_eq!(
        persons
            .desc
            .columns
            .iter()
            .filter(|column| !column.dropped)
            .map(|column| column.name.as_str())
            .collect::<Vec<_>>(),
        vec!["id", "name", "age"]
    );
}

#[test]
fn alter_type_drop_attribute_cascade_drops_dependent_check_constraint() {
    let db = Database::open_ephemeral(32).expect("open ephemeral database");
    db.execute(1, "create type attr_dep_pair as (a int4, b text)")
        .unwrap();
    db.execute(
        1,
        "create table attr_dep_items (id int4, payload attr_dep_pair check ((payload).a > 0))",
    )
    .unwrap();

    let err = db
        .execute(1, "alter type attr_dep_pair drop attribute a")
        .unwrap_err();
    assert!(matches!(
        err,
        ExecError::DetailedError { message, detail, hint, .. }
            if message == "cannot drop column a of composite type attr_dep_pair because other objects depend on it"
                && detail.as_deref() == Some("constraint attr_dep_items_payload_check on table attr_dep_items depends on column a of composite type attr_dep_pair")
                && hint.as_deref() == Some("Use DROP ... CASCADE to drop the dependent objects too.")
    ));

    db.execute(1, "alter type attr_dep_pair drop attribute a cascade")
        .unwrap();
    assert_eq!(
        query_rows(
            &db,
            1,
            "select conname from pg_constraint where conrelid = 'attr_dep_items'::regclass and contype = 'c'",
        ),
        Vec::<Vec<Value>>::new()
    );
    assert_eq!(
        query_rows(
            &db,
            1,
            "select attname from pg_attribute where attrelid = 'attr_dep_pair'::regclass and attnum > 0 and not attisdropped order by attnum",
        ),
        vec![vec![Value::Text("b".into())]]
    );
}

